import React, { useState, useRef, useEffect } from 'react';
import { Upload, X, Plus, Wand2, Sparkles, AlertCircle, ArrowLeft, ArrowRight, ImagePlus, Video, Settings2, RefreshCw, FileDown, History, Clock, Trash2, Maximize2, Download, Monitor, Check, ZoomIn, ZoomOut, RotateCcw, Users, Link as LinkIcon, FileAudio, FileVideo, Info, BookOpen, Zap, ChevronDown, Square, RectangleHorizontal, RectangleVertical, Ratio, Tag, Key, HelpCircle, AlertTriangle, BrainCircuit, ArrowUpCircle, Palette, Shirt, Ruler, UserSquare, CheckCircle, Image as ImageIcon, Crown, Gauge } from 'lucide-react';
import { UploadedImage, AspectRatio, FeatureConfig, FeatureMode, HistoryItem } from '../types';
import { generateImage, generateVideo, generateBatchImages, enhancePrompt } from '../services/geminiService';
import { generateWithPollinations } from '../services/pollinationsService';
import { upscaleImage } from '../services/huggingfaceService';
import { processVideoLink, DownloadResult } from '../services/downloaderService';
import { PromptLibrary } from './PromptLibrary';
import { FeatureExample } from './FeatureExamples';

interface ImageMergerProps {
  feature: FeatureConfig;
  onNavigate: (mode: FeatureMode) => void;
}

const MAX_PROMPT_LENGTH = 1000;

const getImageLabel = (index: number, mode: FeatureMode) => {
  if (mode === 'faceswap') {
    return index === 0 ? 'SUMBER WAJAH (Face)' : 'TARGET FOTO (Body)';
  }
  if (mode === 'videofaceswap') {
    return index === 0 ? 'Wajah (Sumber)' : `Ref #${index + 1}`;
  }
  if (mode === 'fitting') {
    return index === 0 ? 'Model/Orang' : 'Baju/Garmen';
  }
  if (mode === 'prewedding') {
    return index === 0 ? 'Foto Pria' : 'Foto Wanita';
  }
  if (mode === 'mockup') {
    return index === 0 ? 'Desain/Logo' : 'Objek Mockup';
  }
  if (mode === 'veo') {
    return index === 0 ? 'Referensi Awal' : `Ref #${index + 1}`;
  }
  if (mode === 'removebg' || mode === 'removeobj') {
    return 'Foto Asli';
  }
  if (mode === 'fotomodel') {
    return 'Foto Produk / Baju';
  }
  if (mode === 'banana') {
    return 'Reference (Opt)';
  }
  if (mode === 'passphoto') {
    return 'Foto Asli';
  }
  return `#${index + 1}`;
};

const ImageMerger: React.FC<ImageMergerProps> = ({ feature, onNavigate }) => {
  const [images, setImages] = useState<UploadedImage[]>([]);
  const [prompt, setPrompt] = useState<string>(feature.defaultPrompt);
  const [ratio, setRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [showPromptLib, setShowPromptLib] = useState(false);
  const [aiEngine, setAiEngine] = useState<'gemini' | 'pollinations'>('gemini');
  const [generatedResults, setGeneratedResults] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [videoQuality, setVideoQuality] = useState<'720p' | '1080p' | '4k'>('1080p');
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [downloadingQuality, setDownloadingQuality] = useState<string | null>(null);
  const [isUpscaling, setIsUpscaling] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [downloadUrlInput, setDownloadUrlInput] = useState('');
  const [downloadFormat, setDownloadFormat] = useState('mp4-1080p');
  const [downloadProgress, setDownloadProgress] = useState(0);
  const [downloadResult, setDownloadResult] = useState<DownloadResult | null>(null);
  const [genProgress, setGenProgress] = useState<{ current: number; total: number }>({ current: 0, total: 0 });

  // Model Customization State
  const [modelGender, setModelGender] = useState('Wanita');
  const [modelAge, setModelAge] = useState('Dewasa Muda (20-28 thn)');
  const [modelRace, setModelRace] = useState('Asia (Indonesia/Melayu)');

  // Pas Foto State
  const [passBg, setPassBg] = useState('Merah');
  const [passOutfit, setPassOutfit] = useState('Kemeja Putih Polos');
  const [passSize, setPassSize] = useState('4x6');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const isVideoMode = feature.type === 'video';
  const isDownloaderMode = feature.type === 'downloader';
  const isTextToImage = feature.id === 'imagine'; 
  const isFaceSwap = feature.id === 'faceswap';
  const isPassPhoto = feature.id === 'passphoto';

  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem('andri_ai_history');
      if (savedHistory) {
        setHistory(JSON.parse(savedHistory));
      }
    } catch (e) {
      console.error("Failed to load history", e);
    }
  }, []);

  useEffect(() => {
    setImages([]);
    setPrompt(feature.defaultPrompt);
    setGeneratedResults([]);
    setError(null);
    setRatio(AspectRatio.SQUARE);

    // Default engine selection
    if (feature.id === 'banana') {
        setAiEngine('pollinations'); // Default to Fast for Banana
    } else {
        setAiEngine('gemini');
    }

    setDownloadUrlInput('');
    setDownloadProgress(0);
    setDownloadResult(null);
    setGenProgress({ current: 0, total: 0 });

    if (isVideoMode) {
        setRatio(AspectRatio.LANDSCAPE);
        setVideoQuality('1080p');
    }
    // Set default ratio for pass photo to match common portrait needs
    if (feature.id === 'passphoto') {
        setRatio(AspectRatio.PORTRAIT_4_5); 
    }
  }, [feature, isVideoMode]);

  useEffect(() => {
    if (previewImage) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
       document.body.style.overflow = 'unset';
    };
  }, [previewImage]);

  const handlePromptChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    if (val.length <= MAX_PROMPT_LENGTH) {
      setPrompt(val);
      setError(null);
    }
  };

  const handleMagicPrompt = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      const enhanced = await enhancePrompt(prompt);
      setPrompt(enhanced);
    } catch (e) {
      // ignore
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newImages = Array.from(e.target.files).map((file: File) => ({
        id: Math.random().toString(36).substr(2, 9),
        file,
        previewUrl: URL.createObjectURL(file),
      }));
      setImages((prev) => [...prev, ...newImages]);

      if (feature.id === 'banana' && aiEngine === 'pollinations') {
          // Keep pollinations unless user switches
      }
    }
  };

  const removeImage = (id: string) => {
    setImages((prev) => prev.filter((img) => img.id !== id));
  };

  const moveImage = (index: number, direction: 'left' | 'right') => {
    if (direction === 'left' && index === 0) return;
    if (direction === 'right' && index === images.length - 1) return;
    const newImages = [...images];
    const targetIndex = direction === 'left' ? index - 1 : index + 1;
    [newImages[index], newImages[targetIndex]] = [newImages[targetIndex], newImages[index]];
    setImages(newImages);
  };

  const handleGenerate = async () => {
    if (images.length < feature.minImages) {
      setError(`Minimal upload ${feature.minImages} gambar untuk fitur ini.`);
      return;
    }
    if (images.length > feature.maxImages && feature.maxImages > 0) {
      setError(`Maksimal upload ${feature.maxImages} gambar.`);
      return;
    }
    if (!prompt.trim() && !isPassPhoto) {
       setError("Instruksi tidak boleh kosong.");
       return;
    }

    setLoading(true);
    setError(null);
    setGeneratedResults([]);
    setGenProgress({ current: 0, total: 0 });

    try {
      let results: string[] = [];
      let finalPrompt = prompt;

      if (feature.id === 'fotomodel') {
         finalPrompt = `Target Model Specification: [Gender: ${modelGender}, Age: ${modelAge}, Ethnicity: ${modelRace}]. User Request: ${prompt}`;
      }

      if (feature.id === 'passphoto') {
         const hexColor = passBg === 'Merah' ? '#db1514' : (passBg === 'Biru' ? '#0090e7' : '#FFFFFF');
         finalPrompt = `TASK: PROFESSIONAL PASSPORT PHOTO GENERATION.

         INPUT: User photo.
         OUTPUT: A formal passport photo (Pas Foto).

         SPECIFICATIONS:
         1. BACKGROUND: Solid ${passBg} (Hex approx: ${hexColor}). Clean, flat, no shadows.
         2. OUTFIT/CLOTHING: Change subject's clothes to: "${passOutfit}". Must be formal, neat, symmetrical, high-quality fabric texture.
         3. POSE & FACE: Front-facing, neutral formal expression, eyes open looking at camera.
         4. RETOUCHING: Professional skin retouching, fix lighting to be even studio lighting, remove blemishes, neat hair/hijab.
         5. RATIO/CROP: Format ${passSize} (Portrait).

         The result must look like a real photo taken in a professional studio for official documents (KTP/Passport/Visa). High Resolution.`;
      }

      if (isVideoMode) {
        const videoUrl = await generateVideo(finalPrompt, images, ratio, feature.id, videoQuality);
        results = [videoUrl];
      } else if (aiEngine === 'pollinations') {
        setGenProgress({ current: 0, total: 4 });
        let w = 1024, h = 1024;
        if (ratio === AspectRatio.LANDSCAPE) { w = 1280; h = 720; }
        else if (ratio === AspectRatio.PORTRAIT) { w = 720; h = 1280; }
        else if (ratio === AspectRatio.PORTRAIT_4_5) { w = 864; h = 1080; }
        else if (ratio === AspectRatio.LANDSCAPE_5_4) { w = 1080; h = 864; }

        for (let i = 0; i < 4; i++) {
             try {
                 const res = await generateWithPollinations(finalPrompt, w, h);
                 results.push(res);
                 setGenProgress(prev => ({ ...prev, current: prev.current + 1 }));
             } catch (pollinationErr: any) {
                 console.warn(`Pollinations item ${i} failed:`, pollinationErr);
             }
        }

        if (results.length === 0) {
            throw new Error("Gagal membuat gambar dengan Pollinations (Semua percobaan gagal).");
        }

      } else {
        results = await generateBatchImages(
          finalPrompt, 
          images, 
          ratio, 
          feature.id, 
          4,
          (current, total) => {
             setGenProgress({ current, total });
          }
        );
      }

      setGeneratedResults(results);

      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        mode: feature.id,
        prompt: isPassPhoto ? `Pas Foto: ${passOutfit} - ${passBg}` : prompt,
        results: results,
        thumbnail: results[0],
        type: feature.type || 'image'
      };

      const updatedHistory = [newHistoryItem, ...history].slice(50);
      setHistory(updatedHistory);
      localStorage.setItem('andri_ai_history', JSON.stringify(updatedHistory));

    } catch (err: any) {
      const errorMsg = err.message || 'Gagal memproses permintaan.';
      const isPermissionError = 
         errorMsg.toLowerCase().includes('permission') || 
         errorMsg.toLowerCase().includes('izin') || 
         errorMsg.includes('403');

      const isQuotaError = errorMsg.includes('429') || errorMsg.includes('Quota');

      if (!isPermissionError) {
         setError(errorMsg);
      } else {
         console.warn("Suppressed permission error notification:", errorMsg);
      }

      if (isQuotaError && images.length === 0 && aiEngine === 'gemini') {
         console.warn("Gemini Quota Full. Attempting automatic fallback to Pollinations...");
         try {
             setError(null); 
             setAiEngine('pollinations');

             setGenProgress({ current: 0, total: 4 });
             let w = 1024, h = 1024;
             if (ratio === AspectRatio.LANDSCAPE) { w = 1280; h = 720; }
             else if (ratio === AspectRatio.PORTRAIT) { w = 720; h = 1280; }

             const rescueResults: string[] = [];
             for (let i = 0; i < 4; i++) {
                 try {
                     const res = await generateWithPollinations(prompt, w, h);
                     rescueResults.push(res);
                     setGenProgress(prev => ({ ...prev, current: prev.current + 1 }));
                 } catch (e) {
                     console.warn("Rescue item failed", e);
                 }
             }

             if (rescueResults.length > 0) {
                 setGeneratedResults(rescueResults);
                 setLoading(false);
                 return;
             } else {
                 throw new Error("Rescue fallback failed.");
             }

         } catch (rescueErr) {
             console.error("Rescue failed", rescueErr);
             setError("Gagal generate (Gemini Quota Full & Fallback Failed). Silakan coba lagi nanti.");
         }
      }

    } finally {
      setLoading(false);
      setGenProgress({ current: 0, total: 0 });
    }
  };

  const handleConvertVideo = async () => {
     if(!downloadUrlInput.trim()) {
        setError("Silakan masukkan URL video terlebih dahulu.");
        return;
     }
     setLoading(true);
     setError(null);
     setDownloadProgress(0);
     setDownloadResult(null);

     try {
        const result = await processVideoLink(
           downloadUrlInput, 
           feature.id, 
           downloadFormat,
           (progress) => setDownloadProgress(progress)
        );
        setDownloadResult(result);
     } catch (err: any) {
        setError(err.message || "Gagal mengkonversi video.");
     } finally {
        setLoading(false);
     }
  };

  const openPreview = (url: string) => {
    setPreviewImage(url);
    setZoom(1);
    setPan({ x: 0, y: 0 });
  };

  const handleUpscalePreview = async () => {
      if (!previewImage) return;
      if (feature.type === 'video' || previewImage.includes('video')) {
          alert("Upscaling hanya tersedia untuk gambar.");
          return;
      }
      setIsUpscaling(true);
      try {
          const response = await fetch(previewImage);
          const blob = await response.blob();
          const upscaledUrl = await upscaleImage(blob);
          setPreviewImage(upscaledUrl);
          setGeneratedResults(prev => [...prev, upscaledUrl]);
      } catch (err: any) {
          alert(`Gagal upscale: ${err.message}`);
      } finally {
          setIsUpscaling(false);
      }
  };

  const handleDownload = async (url: string, quality: 'HD' | 'FHD' | 'UHD' = 'HD') => {
    if (isVideoMode) {
      window.open(url, '_blank');
      return;
    }
    try {
      setDownloadingQuality(quality);
      let scaleFactor = 1;
      if (quality === 'FHD') scaleFactor = 2;
      if (quality === 'UHD') scaleFactor = 4;

      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = url;
      await new Promise(resolve => { img.onload = resolve; });

      const canvas = document.createElement('canvas');
      canvas.width = img.width * scaleFactor;
      canvas.height = img.height * scaleFactor;

      const ctx = canvas.getContext('2d');
      if (!ctx) throw new Error("Canvas context failed");

      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

      const dataUrl = canvas.toDataURL('image/png', 1.0);
      const link = document.createElement('a');
      link.href = dataUrl;
      link.download = `AndriAI-Pro-${feature.id}-${Date.now()}-${quality}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (e) {
      console.error("Download failed", e);
      alert("Gagal mendownload gambar.");
    } finally {
      setDownloadingQuality(null);
    }
  };

