/**
 * Helper to parse error details
 */
const parseError = (error: any) => {
  const errString = JSON.stringify(error, Object.getOwnPropertyNames(error));

  // Try to extract a clean message
  let message = '';
  if (error?.message) message = error.message;
  else if (error?.error?.message) message = error.error.message;
  else if (typeof error === 'string') message = error;
  else message = "Unknown error occurred";

  // Robust check for permission codes (403)
  const status = error?.status || error?.error?.status;
  const code = error?.code || error?.error?.code;
  const responseStatus = error?.response?.status;

  const isPermissionError = 
    status === 'PERMISSION_DENIED' || 
    code === 403 || 
    responseStatus === 403 ||
    errString.includes('403') || 
    errString.includes('PERMISSION_DENIED') || 
    message.includes('403') ||
    message.toLowerCase().includes('permission') ||
    message.toLowerCase().includes('access denied');

  // Check for Quota Exceeded (429)
  const isQuotaError = 
    status === 'RESOURCE_EXHAUSTED' || 
    code === 429 || 
    responseStatus === 429 ||
    errString.includes('429') || 
    errString.includes('RESOURCE_EXHAUSTED') ||
    message.includes('quota') ||
    message.includes('Quota') ||
    message.includes('429') ||
    message.includes('RESOURCE_EXHAUSTED');

  const isServerError = 
    errString.includes('500') || 
    errString.includes('INTERNAL') || 
    status === 500 ||
    code === 500;

  return { isPermissionError, isQuotaError, isServerError, message };
};

/**
 * Helper: Convert Base64 PCM to WAV Base64
 * Gemini TTS returns raw PCM (24kHz, 1 channel, 16-bit).
 * Browser <audio> needs WAV/MP3 container.
 */
const pcmToWav = (base64PCM: string): string => {
  const binaryString = atob(base64PCM);
  const len = binaryString.length;
  const buffer = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    buffer[i] = binaryString.charCodeAt(i);
  }

  // WAV Header params
  const numChannels = 1;
  const sampleRate = 24000;
  const bitsPerSample = 16;
  const blockAlign = numChannels * bitsPerSample / 8;
  const byteRate = sampleRate * blockAlign;
  const dataSize = len;

  const bufferHeader = new ArrayBuffer(44);
  const view = new DataView(bufferHeader);

  // RIFF identifier
  writeString(view, 0, 'RIFF');
  // file length
  view.setUint32(4, 36 + dataSize, true);
  // RIFF type
  writeString(view, 8, 'WAVE');
  // format chunk identifier
  writeString(view, 12, 'fmt ');
  // format chunk length
  view.setUint32(16, 16, true);
  // sample format (raw)
  view.setUint16(20, 1, true);
  // channel count
  view.setUint16(22, numChannels, true);
  // sample rate
  view.setUint32(24, sampleRate, true);
  // byte rate (sample rate * block align)
  view.setUint32(28, byteRate, true);
  // block align (channel count * bytes per sample)
  view.setUint16(32, blockAlign, true);
  // bits per sample
  view.setUint16(34, bitsPerSample, true);
  // data chunk identifier
  writeString(view, 36, 'data');
  // data chunk length
  view.setUint32(40, dataSize, true);

  // Concatenate Header + Data
  const wavBytes = new Uint8Array(44 + dataSize);
  wavBytes.set(new Uint8Array(bufferHeader), 0);
  wavBytes.set(buffer, 44);

  // Convert back to base64
  let binary = '';
  const bytes = wavBytes;
  const l = bytes.byteLength;
  for (let i = 0; i < l; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return `data:audio/wav;base64,${btoa(binary)}`;
};

const writeString = (view: DataView, offset: number, string: string) => {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
};


/**
 * Magic Prompt with Fallback
 */
export const enhancePrompt = async (originalPrompt: string): Promise<string> => {
  try {
    const apiKey = getApiKey();
    const ai = new GoogleGenAI({ apiKey });

    try {
        const response = await ai.models.generateContent({
          model: PRIMARY_CHAT_MODEL,
          contents: {
            parts: [{ text: `You are an expert AI Prompt Engineer. Rewrite this prompt to be highly detailed and artistic for image generation: "${originalPrompt}". Output ONLY the raw prompt.` }]
          }
        });
        return response.text?.trim() || originalPrompt;
    } catch(err: any) {
        const { isPermissionError, isQuotaError } = parseError(err);
        if (!isQuotaError) {
             console.warn("Enhance prompt warning:", err.message);
        }
        return originalPrompt;
    }

  } catch (e) {
    return originalPrompt;
  }
};

/**
 * Generate Speech (TTS)
 */
export const generateSpeech = async (text: string, voiceName: string = 'Kore'): Promise<string> => {
    try {
        const apiKey = getApiKey();
        const ai = new GoogleGenAI({ apiKey });

        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: voiceName },
                    },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) {
            throw new Error("No audio data returned from Gemini TTS.");
        }

        // Convert raw PCM to WAV so it can be played in browser <audio>
        return pcmToWav(base64Audio);

    } catch (error: any) {
        const { message } = parseError(error);
        console.error("TTS Error:", error);
        throw new Error(`Gagal membuat suara: ${message}`);
    }
};

/**
 * Main Image Generation Function with Fallback
 */
export const generateImage = async (
  prompt: string,
  images: UploadedImage[],
  ratio: AspectRatio,
  mode: FeatureMode,
  retries = 2,
  useFallback = false
): Promise<string> => {
  try {
    const apiKey = getApiKey();
    if (!apiKey) await ensureApiKey();

    const finalApiKey = getApiKey();
    if (!finalApiKey) throw new Error("API Key tidak ditemukan.");

    const ai = new GoogleGenAI({ apiKey: finalApiKey });
    const imageParts = await Promise.all(images.map((img) => fileToGenerativePart(img.file)));

    // Use fallback model if flag is set
    const modelName = useFallback ? FALLBACK_IMAGE_MODEL : PRIMARY_IMAGE_MODEL;

    let systemContext = "Task: Advanced Image Generation. Create a photorealistic high-quality image.";

    if (mode === 'removebg') systemContext += " Remove background, subject on pure white background.";

    if (mode === 'faceswap') {
        systemContext = `TASK: PRECISION FACE REPLACEMENT (IDENTITY TRANSFER).

        INPUTS:
        - Image 1: REFERENCE FACE (Identity Source).
        - Image 2: TARGET BODY (Environment/Pose).

        INSTRUCTION:
        Generate a new image where the face of the person in Image 2 is REPLACED by the face of the person in Image 1.

        STRICT REQUIREMENTS:
        1. IDENTITY: The resulting face MUST be an exact biological match to Image 1 (Reference Face). Copy facial structure, eyes, nose, mouth, unique features, and skin texture exactly.
        2. BLENDING: The new face must blend seamlessly with the neck, hair, and head shape of Image 2. No visible seams or color mismatch.
        3. LIGHTING: Adjust the skin tone and lighting of the new face to perfectly match the environment and lighting conditions of Image 2.
        4. EXPRESSION: Maintain the angle and pose of Image 2, but adapt the expression to be natural.
        5. QUALITY: High definition, photorealistic, no distortion, no artifacts, no warping.

        OUTPUT: A single seamless photo.`;
    }

    const strictPrompt = `SYSTEM INSTRUCTION: ${systemContext}

    USER REQUEST: ${prompt}

    Target Aspect Ratio: ${ratio}`;

    const contents = {
        parts: [
            ...imageParts,
            { text: strictPrompt }
        ]
    };

    const response = await ai.models.generateContent({
      model: modelName,
      contents: contents,
      config: { temperature: 0.4 }
    });

    const candidates = response.candidates;
    if (candidates && candidates[0] && candidates[0].content && candidates[0].content.parts) {
        for (const part of candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.data) {
                return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
            }
        }
        if (candidates[0].content.parts[0].text) {
             throw new Error("Gemini Text Response (Not Image): " + candidates[0].content.parts[0].text);
        }
    }

    throw new Error("No image data found in response.");

  } catch (error: any) {
    const { isPermissionError, isQuotaError, isServerError, message } = parseError(error);

    // 0. Quota Error (429) - Handle immediately and cleanly
    if (isQuotaError) {
        console.warn("Gemini Quota Exceeded (429)");
        throw new Error("Kuota API Gemini Habis (429). Silakan ganti ke Mode Banana (Fast) yang gratis.");
    }

    // 1. Automatic Fallback for Permission Error (403)
    if (isPermissionError && !useFallback) {
        console.warn("Permission denied for Pro model. Switching to Flash Image...");
        return await generateImage(prompt, images, ratio, mode, retries, true);
    }

    if (isPermissionError) {
         throw new Error("Akses Ditolak (403). API Key Anda mungkin tidak memiliki izin.");
    }

    // 2. Retry Logic for Server Errors
    if (retries > 0 && (isServerError || message.includes('FetchFailure') || message.includes('text instead of image'))) {
        console.warn(`Retrying... (${retries} attempts left)`);
        await delay(2000);
        return await generateImage(prompt, images, ratio, mode, retries - 1, useFallback || message.includes('text instead of image'));
    }

    // Log generic errors that are NOT quota errors
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

/**
 * Sequential Batch Generation - Resilient Mode
 */
export const generateBatchImages = async (
    prompt: string, 
    images: UploadedImage[], 
    ratio: AspectRatio, 
    mode: FeatureMode,
    count: number = 4,
    onProgress?: (current: number, total: number) => void
): Promise<string[]> => {
    const results: string[] = [];
    let forceFallback = false;

    for (let i = 0; i < count; i++) {
        if (onProgress) onProgress(i + 1, count);

        try {
            const variationPrompt = i === 0 ? prompt : `${prompt} . Variation ${i+1}, distinct style and angle.`;
            const result = await generateImage(variationPrompt, images, ratio, mode, 2, forceFallback);
            results.push(result);
        } catch (e: any) {
            const { isPermissionError, isQuotaError, message } = parseError(e);

            // If Quota Exceeded, STOP IMMEDIATELY.
            // Check both the parsed error AND the message content for "Kuota" (our custom error)
            if (isQuotaError || message.includes('Kuota') || message.includes('429')) {
                 console.warn("Aborting batch due to Quota Error");
                 if (results.length === 0) {
                     // Rethrow so UI can handle fallback
                     throw new Error("Kuota API Habis (429). Silakan ganti ke Mode Banana (Fast).");
                 }
                 break; 
            }

            console.error(`Batch item ${i+1} failed`, e);
            if (isPermissionError) forceFallback = true;
        }
    }

    if (results.length === 0) {
        throw new Error("Gagal membuat gambar (Semua percobaan gagal). Periksa koneksi dan Kuota API Key Anda.");
    }

    return results;
};

/**
 * Video Generation using Google Veo
 */
export const generateVideo = async (
    prompt: string,
    images: UploadedImage[],
    ratio: AspectRatio,
    mode: FeatureMode,
    quality: '720p' | '1080p' | '4k' = '1080p'
): Promise<string> => {
    try {
        await ensureApiKey(); 
        const apiKey = getApiKey();
        const ai = new GoogleGenAI({ apiKey });

        let veoRatio = '16:9';
        if (ratio === AspectRatio.PORTRAIT || ratio === AspectRatio.PORTRAIT_4_5) veoRatio = '9:16';

        // Use 'veo-3.1-fast-generate-preview' if not 4K to save tokens/time
        let model = 'veo-3.1-fast-generate-preview'; 

        let imagePart = null;
        if (images.length > 0) {
            const { inlineData } = await fileToGenerativePart(images[0].file);
            imagePart = {
                imageBytes: inlineData.data,
                mimeType: inlineData.mimeType
            };
        }

        let operation = await ai.models.generateVideos({
            model: model,
            prompt: prompt,
            image: imagePart || undefined,
            config: {
                numberOfVideos: 1,
                aspectRatio: veoRatio as any,
                resolution: quality === '720p' ? '720p' : '1080p' 
            }
        });

        while (!operation.done) {
            await delay(5000);
            operation = await ai.operations.getVideosOperation({ operation: operation });
        }

        if (operation.response?.generatedVideos?.[0]?.video?.uri) {
            return `${operation.response.generatedVideos[0].video.uri}&key=${apiKey}`;
        }

        throw new Error("Video generation completed but no URI returned.");

    } catch (error: any) {
        console.error("Veo Error:", error);
        const { isPermissionError, isQuotaError, message } = parseError(error);

        if (isQuotaError) {
             throw new Error("Kuota Video Habis (429).");
        }
        if (isPermissionError) {
             throw new Error("Akses Ditolak ke Google Veo. Fitur Video memerlukan API Key dengan akses Trusted Tester atau Billing aktif.");
        }

        throw new Error(`Gagal membuat video: ${message}`);
    }
};

/**
 * Chat with Gemini
 */
export const chatWithGemini = async (history: ChatMessage[], newMessage: string): Promise<string> => {
    try {
        const apiKey = getApiKey();
        const ai = new GoogleGenAI({ apiKey });

        const chatHistory = history.map(msg => ({
            role: msg.role,
            parts: [{ text: msg.text }]
        }));

        try {
            const chat = ai.chats.create({
                model: PRIMARY_CHAT_MODEL,
                history: chatHistory,
                config: { systemInstruction: "You are Andri AI Assistant." }
            });
            const result = await chat.sendMessage({ message: newMessage });
            return result.text || "No response.";
        } catch (err: any) {
             const { isPermissionError, isQuotaError } = parseError(err);
             if (isPermissionError || isQuotaError) {
                 const fallbackChat = ai.chats.create({
                    model: FALLBACK_CHAT_MODEL,
                    history: chatHistory
                 });
                 const res = await fallbackChat.sendMessage({ message: newMessage });
                 return res.text || "No response.";
             }
             throw err;
        }
    } catch (error: any) {
        console.error("Chat Error:", error);
        return "Maaf, terjadi kesalahan pada sistem AI.";
    }
};

