import React, { useState, useRef, useEffect } from 'react';
import { Upload, X, Plus, Wand2, Sparkles, AlertCircle, ArrowLeft, ArrowRight, ImagePlus, Video, Settings2, RefreshCw, FileDown, History, Clock, Trash2, Maximize2, Download, Monitor, Check, ZoomIn, ZoomOut, RotateCcw, Users, Link as LinkIcon, FileAudio, FileVideo, Info, BookOpen, Zap, ChevronDown, Square, RectangleHorizontal, RectangleVertical, Ratio, Tag, Key, HelpCircle, AlertTriangle, BrainCircuit, ArrowUpCircle, Palette, Shirt, Ruler, UserSquare, CheckCircle, Image as ImageIcon, Crown, Gauge, AudioLines, Mic, Play, Pause, Music } from 'lucide-react';
