interface ImageMergerProps {
  feature: FeatureConfig;
  onNavigate: (mode: FeatureMode) => void;
}

const MAX_PROMPT_LENGTH = 5000; // Increased for TTS

const getImageLabel = (index: number, mode: FeatureMode) => {
  if (mode === 'faceswap') return index === 0 ? 'SUMBER WAJAH (Face)' : 'TARGET FOTO (Body)';
  if (mode === 'videofaceswap') return index === 0 ? 'Wajah (Sumber)' : `Ref #${index + 1}`;
  if (mode === 'fitting') return index === 0 ? 'Model/Orang' : 'Baju/Garmen';
  if (mode === 'prewedding') return index === 0 ? 'Foto Pria' : 'Foto Wanita';
  if (mode === 'mockup') return index === 0 ? 'Desain/Logo' : 'Objek Mockup';
  if (mode === 'veo') return index === 0 ? 'Referensi Awal' : `Ref #${index + 1}`;
  if (mode === 'removebg' || mode === 'removeobj') return 'Foto Asli';
  if (mode === 'fotomodel') return 'Foto Produk / Baju';
  if (mode === 'banana') return 'Reference (Opt)';
  if (mode === 'passphoto') return 'Foto Asli';
  return `#${index + 1}`;
};

const ImageMerger: React.FC<ImageMergerProps> = ({ feature, onNavigate }) => {
  const [images, setImages] = useState<UploadedImage[]>([]);
  const [prompt, setPrompt] = useState<string>(feature.defaultPrompt);
  const [ratio, setRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [showPromptLib, setShowPromptLib] = useState(false);
  const [aiEngine, setAiEngine] = useState<'gemini' | 'pollinations'>('gemini');
  const [generatedResults, setGeneratedResults] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [videoQuality, setVideoQuality] = useState<'720p' | '1080p' | '4k'>('1080p');
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [downloadingQuality, setDownloadingQuality] = useState<string | null>(null);
  const [isUpscaling, setIsUpscaling] = useState(false);
  const [downloadUrlInput, setDownloadUrlInput] = useState('');
  const [downloadProgress, setDownloadProgress] = useState(0);
  const [downloadResult, setDownloadResult] = useState<DownloadResult | null>(null);
  const [genProgress, setGenProgress] = useState<{ current: number; total: number }>({ current: 0, total: 0 });

  // TTS State
  const [voiceName, setVoiceName] = useState('Kore');

  // Model Customization State
  const [modelGender, setModelGender] = useState('Wanita');
  const [modelAge, setModelAge] = useState('Dewasa Muda (20-28 thn)');
  const [modelRace, setModelRace] = useState('Asia (Indonesia/Melayu)');

  // Pas Foto State
  const [passBg, setPassBg] = useState('Merah');
  const [passOutfit, setPassOutfit] = useState('Kemeja Putih Polos');
  const [passSize, setPassSize] = useState('4x6');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const isVideoMode = feature.type === 'video';
  const isAudioMode = feature.type === 'audio';
  const isDownloaderMode = feature.type === 'downloader';
  const isTextToImage = feature.id === 'imagine'; 
  const isFaceSwap = feature.id === 'faceswap';
  const isPassPhoto = feature.id === 'passphoto';

  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem('andri_ai_history');
      if (savedHistory) {
        setHistory(JSON.parse(savedHistory));
      }
    } catch (e) {
      console.error("Failed to load history", e);
    }
  }, []);

  useEffect(() => {
    setImages([]);
    setPrompt(feature.defaultPrompt);
    setGeneratedResults([]);
    setError(null);
    setRatio(AspectRatio.SQUARE);

    if (feature.id === 'banana') {
        setAiEngine('pollinations');
    } else {
        setAiEngine('gemini');
    }

    setDownloadUrlInput('');
    setDownloadProgress(0);
    setDownloadResult(null);
    setGenProgress({ current: 0, total: 0 });

    if (isVideoMode) {
        setRatio(AspectRatio.LANDSCAPE);
        setVideoQuality('1080p');
    }
    if (feature.id === 'passphoto') {
        setRatio(AspectRatio.PORTRAIT_4_5); 
    }
  }, [feature, isVideoMode]);

  const handlePromptChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    if (val.length <= MAX_PROMPT_LENGTH) {
      setPrompt(val);
      setError(null);
    }
  };

  const handleMagicPrompt = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      const enhanced = await enhancePrompt(prompt);
      setPrompt(enhanced);
    } catch (e) {
      // ignore
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newImages = Array.from(e.target.files).map((file: File) => ({
        id: Math.random().toString(36).substr(2, 9),
        file,
        previewUrl: URL.createObjectURL(file),
      }));
      setImages((prev) => [...prev, ...newImages]);
    }
  };

  const removeImage = (id: string) => {
    setImages((prev) => prev.filter((img) => img.id !== id));
  };

  const handleGenerate = async () => {
    // Validation
    if (!isAudioMode && !isDownloaderMode) {
        if (images.length < feature.minImages) {
          setError(`Minimal upload ${feature.minImages} gambar untuk fitur ini.`);
          return;
        }
        if (images.length > feature.maxImages && feature.maxImages > 0) {
          setError(`Maksimal upload ${feature.maxImages} gambar.`);
          return;
        }
    }
    if (!prompt.trim() && !isPassPhoto && !isDownloaderMode) {
       setError("Instruksi tidak boleh kosong.");
       return;
    }

    setLoading(true);
    setError(null);
    setGeneratedResults([]);
    setGenProgress({ current: 0, total: 0 });

    try {
      let results: string[] = [];
      let finalPrompt = prompt;

      // Special Prompts Construction
      if (feature.id === 'fotomodel') {
         finalPrompt = `Target: Professional Fashion Photography. Model: ${modelGender}, ${modelAge}, ${modelRace}. Action: Wearing the product shown in input image. Context: ${prompt}. Quality: 8k, photorealistic.`;
      }
      if (feature.id === 'passphoto') {
         finalPrompt = `Pas Foto Formal Resmi. Background: ${passBg}. Outfit: ${passOutfit}. Subjek: Wajah dari gambar input. Pencahayaan studio rata, ekspresi netral, mata menatap kamera, resolusi tinggi, tajam.`;
      }

      // --- EXECUTION BLOCK ---

      // 1. Text to Speech
      if (isAudioMode) {
          const audioBase64 = await generateSpeech(prompt, voiceName);
          results = [audioBase64];
      }
      // 2. Video Generation
      else if (isVideoMode) {
         const videoUrl = await generateVideo(finalPrompt, images, ratio, feature.id, videoQuality);
         results = [videoUrl];
      }
      // 3. Fast Image (Banana/Pollinations)
      else if (aiEngine === 'pollinations') {
         // Map AspectRatio to pixels
         let w = 1024, h = 1024;
         if (ratio === AspectRatio.LANDSCAPE) { w = 1280; h = 720; }
         if (ratio === AspectRatio.PORTRAIT) { w = 720; h = 1280; }
         if (ratio === AspectRatio.PORTRAIT_4_5) { w = 864; h = 1080; }

         const imageUrl = await generateWithPollinations(finalPrompt, w, h);
         results = [imageUrl];
      }
      // 4. Gemini Image Generation
      else {
         if (feature.id === 'banana') {
            // "Banana Pro" logic using Gemini Batch
            results = await generateBatchImages(finalPrompt, images, ratio, feature.id, 4, (c, t) => setGenProgress({current:c, total:t}));
         } else {
            // Standard Gemini Single Generation
            const result = await generateImage(finalPrompt, images, ratio, feature.id);
            results = [result];
         }
      }

      setGeneratedResults(results);

      // Save to History
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        mode: feature.id,
        prompt: finalPrompt,
        results: results,
        thumbnail: results[0],
        type: feature.type || 'image'
      };

      const updatedHistory = [newHistoryItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('andri_ai_history', JSON.stringify(updatedHistory));

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Gagal memproses permintaan. Silakan coba lagi.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadUrl = async () => {
     if (!downloadUrlInput) { setError("URL tidak boleh kosong"); return; }
     setLoading(true);
     setDownloadProgress(10);
     try {
        const result = await processVideoLink(downloadUrlInput, feature.id, 'mp4-1080p', (p) => setDownloadProgress(p));
        setDownloadResult(result);
     } catch(e: any) {
        setError(e.message);
     } finally {
