interface ImageMergerProps {
  feature: FeatureConfig;
  onNavigate: (mode: FeatureMode) => void;
}

const MAX_PROMPT_LENGTH = 5000; // Increased for TTS

const getImageLabel = (index: number, mode: FeatureMode) => {
  if (mode === 'faceswap') return index === 0 ? 'SUMBER WAJAH (Face)' : 'TARGET FOTO (Body)';
  if (mode === 'videofaceswap') return index === 0 ? 'Wajah (Sumber)' : `Ref #${index + 1}`;
  if (mode === 'fitting') return index === 0 ? 'Model/Orang' : 'Baju/Garmen';
  if (mode === 'prewedding') return index === 0 ? 'Foto Pria' : 'Foto Wanita';
  if (mode === 'mockup') return index === 0 ? 'Desain/Logo' : 'Objek Mockup';
  if (mode === 'veo') return index === 0 ? 'Referensi Awal' : `Ref #${index + 1}`;
  if (mode === 'removebg' || mode === 'removeobj') return 'Foto Asli';
  if (mode === 'fotomodel') return 'Foto Produk / Baju';
  if (mode === 'banana') return 'Reference (Opt)';
  if (mode === 'passphoto') return 'Foto Asli';
  return `#${index + 1}`;
};

const ImageMerger: React.FC<ImageMergerProps> = ({ feature, onNavigate }) => {
  const [images, setImages] = useState<UploadedImage[]>([]);
  const [prompt, setPrompt] = useState<string>(feature.defaultPrompt);
  const [ratio, setRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [showPromptLib, setShowPromptLib] = useState(false);
  const [aiEngine, setAiEngine] = useState<'gemini' | 'pollinations'>('gemini');
  const [generatedResults, setGeneratedResults] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [videoQuality, setVideoQuality] = useState<'720p' | '1080p' | '4k'>('1080p');
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [downloadingQuality, setDownloadingQuality] = useState<string | null>(null);
  const [isUpscaling, setIsUpscaling] = useState(false);
  const [downloadUrlInput, setDownloadUrlInput] = useState('');
  const [downloadProgress, setDownloadProgress] = useState(0);
  const [downloadResult, setDownloadResult] = useState<DownloadResult | null>(null);
  const [genProgress, setGenProgress] = useState<{ current: number; total: number }>({ current: 0, total: 0 });

  // TTS State
  const [voiceName, setVoiceName] = useState('Kore');

  // Model Customization State
  const [modelGender, setModelGender] = useState('Wanita');
  const [modelAge, setModelAge] = useState('Dewasa Muda (20-28 thn)');
  const [modelRace, setModelRace] = useState('Asia (Indonesia/Melayu)');

  // Pas Foto State
  const [passBg, setPassBg] = useState('Merah');
  const [passOutfit, setPassOutfit] = useState('Kemeja Putih Polos');
  const [passSize, setPassSize] = useState('4x6');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const isVideoMode = feature.type === 'video';
  const isAudioMode = feature.type === 'audio';
  const isDownloaderMode = feature.type === 'downloader';
  const isTextToImage = feature.id === 'imagine'; 
  const isFaceSwap = feature.id === 'faceswap';
  const isPassPhoto = feature.id === 'passphoto';

  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem('andri_ai_history');
      if (savedHistory) {
        setHistory(JSON.parse(savedHistory));
      }
    } catch (e) {
      console.error("Failed to load history", e);
    }
  }, []);

  useEffect(() => {
    setImages([]);
    setPrompt(feature.defaultPrompt);
    setGeneratedResults([]);
    setError(null);
    setRatio(AspectRatio.SQUARE);

    if (feature.id === 'banana') {
        setAiEngine('pollinations');
    } else {
        setAiEngine('gemini');
    }

    setDownloadUrlInput('');
    setDownloadProgress(0);
    setDownloadResult(null);
    setGenProgress({ current: 0, total: 0 });

    if (isVideoMode) {
        setRatio(AspectRatio.LANDSCAPE);
        setVideoQuality('1080p');
    }
    if (feature.id === 'passphoto') {
        setRatio(AspectRatio.PORTRAIT_4_5); 
    }
  }, [feature, isVideoMode]);

  const handlePromptChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    if (val.length <= MAX_PROMPT_LENGTH) {
      setPrompt(val);
      setError(null);
    }
  };

  const handleMagicPrompt = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      const enhanced = await enhancePrompt(prompt);
      setPrompt(enhanced);
    } catch (e) {
      // ignore
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newImages = Array.from(e.target.files).map((file: File) => ({
        id: Math.random().toString(36).substr(2, 9),
        file,
        previewUrl: URL.createObjectURL(file),
      }));
      setImages((prev) => [...prev, ...newImages]);
    }
  };

  const removeImage = (id: string) => {
    setImages((prev) => prev.filter((img) => img.id !== id));
  };

  const handleGenerate = async () => {
    // Validation
    if (!isAudioMode && !isDownloaderMode) {
        if (images.length < feature.minImages) {
          setError(`Minimal upload ${feature.minImages} gambar untuk fitur ini.`);
          return;
        }
        if (images.length > feature.maxImages && feature.maxImages > 0) {
          setError(`Maksimal upload ${feature.maxImages} gambar.`);
          return;
        }
    }
    if (!prompt.trim() && !isPassPhoto && !isDownloaderMode) {
       setError("Instruksi tidak boleh kosong.");
       return;
    }

    setLoading(true);
    setError(null);
    setGeneratedResults([]);
    setGenProgress({ current: 0, total: 0 });

    try {
      let results: string[] = [];
      let finalPrompt = prompt;

      // Special Prompts Construction
      if (feature.id === 'fotomodel') {
         finalPrompt = `Target: Professional Fashion Photography. Model: ${modelGender}, ${modelAge}, ${modelRace}. Action: Wearing the product shown in input image. Context: ${prompt}. Quality: 8k, photorealistic.`;
      }
      if (feature.id === 'passphoto') {
         finalPrompt = `Pas Foto Formal Resmi. Background: ${passBg}. Outfit: ${passOutfit}. Subjek: Wajah dari gambar input. Pencahayaan studio rata, ekspresi netral, mata menatap kamera, resolusi tinggi, tajam.`;
      }

      // --- EXECUTION BLOCK ---

      // 1. Text to Speech
      if (isAudioMode) {
          const audioBase64 = await generateSpeech(prompt, voiceName);
          results = [audioBase64];
      }
      // 2. Video Generation
      else if (isVideoMode) {
         const videoUrl = await generateVideo(finalPrompt, images, ratio, feature.id, videoQuality);
         results = [videoUrl];
      }
      // 3. Fast Image (Banana/Pollinations)
      else if (aiEngine === 'pollinations') {
         // Map AspectRatio to pixels
         let w = 1024, h = 1024;
         if (ratio === AspectRatio.LANDSCAPE) { w = 1280; h = 720; }
         if (ratio === AspectRatio.PORTRAIT) { w = 720; h = 1280; }
         if (ratio === AspectRatio.PORTRAIT_4_5) { w = 864; h = 1080; }

         const imageUrl = await generateWithPollinations(finalPrompt, w, h);
         results = [imageUrl];
      }
      // 4. Gemini Image Generation
      else {
         if (feature.id === 'banana') {
            // "Banana Pro" logic using Gemini Batch
            results = await generateBatchImages(finalPrompt, images, ratio, feature.id, 4, (c, t) => setGenProgress({current:c, total:t}));
         } else {
            // Standard Gemini Single Generation
            const result = await generateImage(finalPrompt, images, ratio, feature.id);
            results = [result];
         }
      }

      setGeneratedResults(results);

      // Save to History
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        mode: feature.id,
        prompt: finalPrompt,
        results: results,
        thumbnail: results[0],
        type: feature.type || 'image'
      };

      const updatedHistory = [newHistoryItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('andri_ai_history', JSON.stringify(updatedHistory));

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Gagal memproses permintaan. Silakan coba lagi.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadUrl = async () => {
     if (!downloadUrlInput) { setError("URL tidak boleh kosong"); return; }
     setLoading(true);
     setDownloadProgress(10);
     try {
        const result = await processVideoLink(downloadUrlInput, feature.id, 'mp4-1080p', (p) => setDownloadProgress(p));
        setDownloadResult(result);
     } catch(e: any) {
        setError(e.message);
     } finally {
        setLoading(false);
     }
  };

  // --- UI COMPONENTS ---

  const renderVoiceSelector = () => (
    <div className="mb-6 animate-in fade-in slide-in-from-left-4">
        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 flex items-center gap-2">
            <Mic size={16} className="text-emerald-500" /> Pilih Suara AI
        </label>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
             {[
                 { id: 'Kore', label: 'Kore', desc: 'Wanita - Tenang & Jelas', gender: 'F' },
                 { id: 'Zephyr', label: 'Zephyr', desc: 'Wanita - Lembut & Empati', gender: 'F' },
                 { id: 'Puck', label: 'Puck', desc: 'Pria - Energik & Ceria', gender: 'M' },
                 { id: 'Charon', label: 'Charon', desc: 'Pria - Berat & Dalam', gender: 'M' },
                 { id: 'Fenrir', label: 'Fenrir', desc: 'Pria - Berwibawa & Kuat', gender: 'M' },
             ].map((voice) => (
                 <div 
                    key={voice.id}
                    onClick={() => setVoiceName(voice.id)}
                    className={`cursor-pointer p-3 rounded-xl border transition-all flex items-center gap-3 ${
                        voiceName === voice.id 
                        ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-500 ring-1 ring-emerald-500' 
                        : 'bg-white dark:bg-white/5 border-slate-200 dark:border-white/10 hover:border-emerald-300'
                    }`}
                 >
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${
                        voiceName === voice.id ? 'bg-emerald-500 text-white' : 'bg-slate-200 dark:bg-white/10 text-slate-500'
                    }`}>
                        {voice.gender}
                    </div>
                    <div>
                        <div className="font-bold text-slate-700 dark:text-slate-200 text-sm">{voice.label}</div>
                        <div className="text-[10px] text-slate-500 dark:text-slate-400">{voice.desc}</div>
                    </div>
                    {voiceName === voice.id && <CheckCircle size={16} className="ml-auto text-emerald-500" />}
                 </div>
             ))}
        </div>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800 dark:text-white flex items-center gap-3">
            <div className="p-2 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl shadow-lg shadow-emerald-500/20 text-white">
               {feature.icon || <Sparkles size={24} />}
            </div>
            {feature.title}
          </h2>
          <p className="text-slate-500 dark:text-slate-400 mt-1 text-sm md:text-base max-w-2xl">
            {feature.description}
          </p>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">

        {/* LEFT COLUMN - CONTROLS */}
        <div className="w-full lg:w-[420px] shrink-0 space-y-6">

            {/* Input Section */}
            <div className="bg-white dark:bg-[#0c0c0e] p-6 rounded-3xl shadow-xl border border-slate-200 dark:border-white/10 relative overflow-hidden">

                {/* Mode Specific Inputs */}

                {/* 1. Downloader Input */}
                {isDownloaderMode && (
                    <div className="mb-6">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Link Video {feature.title.split(' ')[0]}</label>
                        <div className="flex gap-2">
                             <input 
                                type="text"
                                value={downloadUrlInput}
                                onChange={(e) => setDownloadUrlInput(e.target.value)}
                                className="flex-1 p-3 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                                placeholder={`Tempel link ${feature.title.split(' ')[0]} disini...`}
                             />
                        </div>
                    </div>
                )}

                {/* 2. Audio/TTS Voice Selector */}
                {isAudioMode && renderVoiceSelector()}

                {/* 3. Image Uploaders (If not audio/downloader) */}
                {!isAudioMode && !isDownloaderMode && (feature.maxImages > 0) && (
                    <div className="mb-6">
                         <div className="flex justify-between items-center mb-3">
                            <label className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                                <ImagePlus size={16} className="text-emerald-500" />
                                Upload Gambar Referensi
                            </label>
                            <span className="text-xs font-medium bg-slate-100 dark:bg-white/10 px-2 py-1 rounded text-slate-500">
                                {images.length} / {feature.maxImages === 0 ? '∞' : feature.maxImages}
                            </span>
                        </div>

                        <div className="grid grid-cols-2 gap-3 mb-3">
                            {images.map((img, idx) => (
                                <div key={img.id} className="relative aspect-square rounded-xl overflow-hidden border border-slate-200 dark:border-white/10 group bg-slate-100 dark:bg-white/5">
                                    <img src={img.previewUrl} alt="Upload" className="w-full h-full object-cover" />
                                    <button 
                                        onClick={() => removeImage(img.id)}
                                        className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md"
                                    >
                                        <X size={12} />
                                    </button>
                                    <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-[10px] py-1 px-2 text-center backdrop-blur-sm truncate">
                                        {getImageLabel(idx, feature.id)}
                                    </div>
                                </div>
                            ))}

                            {/* Upload Button */}
                            {images.length < (feature.maxImages || 99) && (
                                <div 
                                    onClick={() => fileInputRef.current?.click()}
                                    className="aspect-square rounded-xl border-2 border-dashed border-slate-300 dark:border-white/20 hover:border-emerald-500 dark:hover:border-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/10 flex flex-col items-center justify-center cursor-pointer transition-all group"
                                >
                                    <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-white/10 group-hover:bg-emerald-100 dark:group-hover:bg-emerald-500/20 flex items-center justify-center mb-2 transition-colors">
                                        <Plus size={20} className="text-slate-400 group-hover:text-emerald-500" />
                                    </div>
                                    <span className="text-xs text-slate-500 font-medium group-hover:text-emerald-600">Tambah Foto</span>
                                </div>
                            )}
                        </div>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            onChange={handleFileChange} 
                            className="hidden" 
                            accept="image/*" 
                            multiple 
                        />
                    </div>
                )}

                {/* 4. Prompt Input (Unless Downloader) */}
                {!isDownloaderMode && (
                    <div className="mb-6">
                        <div className="flex justify-between items-center mb-2">
                            <label className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                                {isAudioMode ? <FileText size={16} className="text-emerald-500" /> : <Wand2 size={16} className="text-emerald-500" />}
                                {isAudioMode ? "Teks Narasi (Script)" : "Instruksi AI (Prompt)"}
                            </label>
                            <div className="flex gap-2">
                                <button 
                                    onClick={() => setShowPromptLib(true)}
                                    className="text-xs flex items-center gap-1 text-slate-500 hover:text-emerald-500 transition-colors"
                                    title="Lihat Contoh Prompt"
                                >
                                    <BookOpen size={12} /> Ide Prompt
                                </button>
                                {!isAudioMode && (
                                    <button 
                                        onClick={handleMagicPrompt}
                                        disabled={enhancing || !prompt}
                                        className={`text-xs flex items-center gap-1 transition-colors ${enhancing ? 'text-emerald-500 animate-pulse' : 'text-slate-500 hover:text-purple-500'}`}
                                        title="Perbaiki Prompt dengan AI"
                                    >
                                        <Sparkles size={12} /> {enhancing ? 'Enhancing...' : 'Magic Enhance'}
                                    </button>
                                )}
                            </div>
                        </div>
                        <div className="relative">
                            <textarea
                                value={prompt}
                                onChange={handlePromptChange}
                                className="w-full h-32 p-4 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none resize-none text-sm leading-relaxed custom-scrollbar text-slate-800 dark:text-slate-200"
                                placeholder={isAudioMode ? "Tuliskan teks yang ingin dibacakan oleh AI disini..." : "Deskripsikan dengan detail apa yang ingin Anda buat..."}
                            />
                            <div className="absolute bottom-3 right-3 text-[10px] font-medium text-slate-400">
                                {prompt.length}/{MAX_PROMPT_LENGTH}
                            </div>
                        </div>
                    </div>
                )}

                {/* 5. Additional Settings (Ratio, Models, etc) - Only for Image/Video */}
                {!isAudioMode && !isDownloaderMode && !isFaceSwap && !feature.id.includes('remove') && !feature.id.includes('upscale') && (
                     <div className="grid grid-cols-2 gap-4 mb-6 animate-in fade-in">
                        {/* Aspect Ratio */}
                        <div>
                             <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Rasio Aspek</label>
                             <div className="flex bg-slate-100 dark:bg-white/5 p-1 rounded-lg border border-slate-200 dark:border-white/5">
                                 {[
                                     { r: AspectRatio.SQUARE, icon: <Square size={14} />, label: '1:1' },
                                     { r: AspectRatio.PORTRAIT, icon: <RectangleVertical size={14} />, label: '9:16' },
                                     { r: AspectRatio.LANDSCAPE, icon: <RectangleHorizontal size={14} />, label: '16:9' },
                                 ].map((opt) => (
                                     <button
                                         key={opt.r}
                                         onClick={() => setRatio(opt.r)}
                                         className={`flex-1 py-2 rounded-md flex items-center justify-center gap-1.5 transition-all text-xs font-medium ${
                                             ratio === opt.r 
                                             ? 'bg-white dark:bg-emerald-600 text-emerald-600 dark:text-white shadow-sm' 
                                             : 'text-slate-500 hover:bg-white/50 dark:hover:bg-white/10'
                                         }`}
                                         title={opt.label}
                                     >
                                         {opt.icon} {opt.label}
                                     </button>
                                 ))}
                             </div>
                        </div>
                     </div>
                )}

                {/* 6. Main Action Button */}
                <button
                    onClick={isDownloaderMode ? handleDownloadUrl : handleGenerate}
                    disabled={loading || (isDownloaderMode && !downloadUrlInput)}
                    className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all transform active:scale-95 flex items-center justify-center gap-2 group relative overflow-hidden ${
                        loading 
                        ? 'bg-slate-700 cursor-not-allowed' 
                        : 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 shadow-emerald-500/25'
                    }`}
                >
                    {loading ? (
                       <>
                         <RefreshCw className="animate-spin" size={20} />
                         {isDownloaderMode ? `Memproses Video ${downloadProgress}%` : 
                          (feature.id === 'banana' && genProgress.total > 0 ? `Generating ${genProgress.current}/${genProgress.total}` : 'Sedang Memproses AI...')}
                       </>
                    ) : (
                       <>
                         {isDownloaderMode ? <FileDown size={20} /> : (isAudioMode ? <Play size={20} /> : <Wand2 size={20} />)}
                         {isDownloaderMode ? 'Download Video' : (isAudioMode ? 'Generate Suara' : 'Mulai Generate')}
                       </>
                    )}
                </button>

                {error && (
                    <div className="mt-4 p-3 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900/30 rounded-xl flex items-start gap-3 text-sm text-red-600 dark:text-red-400 animate-in slide-in-from-top-2">
                        <AlertCircle size={16} className="shrink-0 mt-0.5" />
                        <p>{error}</p>
                    </div>
                )}

            </div>

             {/* Examples */}
             <div className="hidden lg:block">
                 <FeatureExample mode={feature.id} />
             </div>
        </div>

        {/* RIGHT COLUMN - RESULTS */}
        <div className="flex-1 min-w-0">
            <div className="bg-slate-100 dark:bg-[#0c0c0e] rounded-3xl border border-slate-200 dark:border-white/10 min-h-[500px] lg:h-[700px] relative overflow-hidden flex flex-col">

                {/* Result Header */}
                <div className="p-4 border-b border-slate-200 dark:border-white/10 flex justify-between items-center bg-white dark:bg-white/5">
                    <h3 className="font-bold text-slate-700 dark:text-white flex items-center gap-2">
                        {isAudioMode ? <Music size={18} className="text-emerald-500" /> : <ImageIcon size={18} className="text-emerald-500" />}
                        Hasil {isAudioMode ? 'Audio' : (isVideoMode ? 'Video' : 'Gambar')}
                    </h3>
                    <div className="flex gap-2">
                        {generatedResults.length > 0 && !isAudioMode && (
                           <button className="text-xs font-bold text-emerald-600 hover:bg-emerald-50 px-3 py-1.5 rounded-lg transition-colors">
                              Download All
                           </button>
                        )}
                    </div>
                </div>

                {/* Content Area */}
                <div className="flex-1 p-4 md:p-8 overflow-y-auto custom-scrollbar bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] bg-fixed">

                    {loading ? (
                        <div className="h-full flex flex-col items-center justify-center text-center animate-in fade-in">
                            <div className="relative mb-8">
                                <div className="absolute inset-0 bg-emerald-500 blur-2xl opacity-20 animate-pulse"></div>
                                <div className="w-24 h-24 bg-white dark:bg-[#1a1a1c] rounded-3xl shadow-2xl flex items-center justify-center relative z-10 border border-white/10">
                                   <Loader2 size={40} className="text-emerald-500 animate-spin" />
                                </div>
                            </div>
                            <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">Sedang Membuat {isAudioMode ? 'Audio' : 'Karya'}...</h3>
                            <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto text-sm">
                                {isAudioMode ? "AI sedang membaca teks Anda dengan intonasi natural." : "AI sedang menyusun piksel demi piksel untuk mewujudkan imajinasi Anda."}
                            </p>
                        </div>
                    ) : generatedResults.length > 0 ? (
                        <div className={`grid gap-6 ${isAudioMode ? 'grid-cols-1' : (generatedResults.length === 1 ? 'grid-cols-1' : 'grid-cols-1 md:grid-cols-2')}`}>
                            {generatedResults.map((res, idx) => (
                                <div key={idx} className="group relative bg-white dark:bg-[#151517] rounded-2xl overflow-hidden shadow-xl border border-slate-200 dark:border-white/10 animate-in zoom-in-95 duration-500">

                                    {/* TTS Audio Player */}
                                    {isAudioMode ? (
                                        <div className="p-8 flex flex-col items-center justify-center min-h-[200px]">
                                            <div className="w-16 h-16 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-full flex items-center justify-center shadow-lg mb-6 animate-bounce-slow">
                                                <Music className="text-white" size={32} />
                                            </div>
                                            <audio controls src={res} className="w-full max-w-md" />
                                            <div className="mt-6 flex gap-4">
                                                <a 
                                                   href={res} 
                                                   download={`AndriAI-Voice-${Date.now()}.wav`}
                                                   className="flex items-center gap-2 px-6 py-2 bg-slate-800 hover:bg-black text-white rounded-full text-sm font-bold transition-all"
                                                >
                                                   <Download size={16} /> Download WAV
                                                </a>
                                            </div>
                                        </div>
                                    ) : (
                                    /* Image/Video Result */
                                        <>
                                            {isVideoMode ? (
                                                <video src={res} controls autoPlay loop className="w-full h-auto" />
                                            ) : (
                                                <img src={res} alt="Generated" className="w-full h-auto object-contain" />
                                            )}

                                            {/* Overlay Actions */}
                                            <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4 backdrop-blur-sm">
                                                <button 
                                                    onClick={() => {
                                                        const link = document.createElement('a');
                                                        link.href = res;
                                                        link.download = `AndriAI-${Date.now()}.${isVideoMode ? 'mp4' : 'png'}`;
                                                        link.click();
                                                    }}
                                                    className="p-3 bg-white text-black rounded-full hover:bg-emerald-400 hover:scale-110 transition-all shadow-lg"
                                                    title="Download"
                                                >
                                                    <Download size={20} />
                                                </button>
                                                {!isVideoMode && (
                                                    <button 
                                                        onClick={() => setPreviewImage(res)}
                                                        className="p-3 bg-white text-black rounded-full hover:bg-purple-400 hover:scale-110 transition-all shadow-lg"
                                                        title="Preview Fullscreen"
                                                    >
                                                        <Maximize2 size={20} />
                                                    </button>
                                                )}
                                            </div>
                                        </>
                                    )}
                                </div>
                            ))}
                        </div>
                    ) : downloadResult ? (
                         /* Downloader Result View */
                         <div className="flex flex-col items-center justify-center h-full animate-in zoom-in">
                            <div className="bg-white dark:bg-[#151517] p-6 rounded-3xl shadow-2xl border border-slate-200 dark:border-white/10 max-w-sm w-full">
                                <img src={downloadResult.thumbnail} alt="Thumb" className="w-full h-48 object-cover rounded-xl mb-4 shadow-md" />
                                <h4 className="font-bold text-lg text-slate-800 dark:text-white line-clamp-2 mb-2">{downloadResult.title}</h4>
                                <div className="flex justify-between text-sm text-slate-500 mb-6">
                                    <span>{downloadResult.format.toUpperCase()}</span>
                                    <span>{downloadResult.size}</span>
                                </div>
                                <a 
                                   href={downloadResult.downloadUrl}
                                   className="block w-full py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-bold text-center rounded-xl transition-all shadow-lg shadow-emerald-500/20"
                                >
                                    Download File
                                </a>
                            </div>
                         </div>
                    ) : (
                        /* Empty State */
                        <div className="h-full flex flex-col items-center justify-center text-center opacity-40 select-none">
                             <div className="w-32 h-32 bg-slate-200 dark:bg-white/5 rounded-full flex items-center justify-center mb-6">
                                {isAudioMode ? <AudioLines size={48} /> : <ImageIcon size={48} />}
                             </div>
                             <p className="text-xl font-medium">Hasil akan muncul disini</p>
                        </div>
                    )}
                </div>
            </div>
        </div>

      </div>

      {/* Prompt Library Modal */}
      {showPromptLib && (
         <PromptLibrary onSelect={(txt) => { setPrompt(txt); setShowPromptLib(false); }} onClose={() => setShowPromptLib(false)} />
      )}

      {/* Fullscreen Preview */}
      {previewImage && (
         <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4">
             <button onClick={() => setPreviewImage(null)} className="absolute top-6 right-6 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white">
                 <X size={24} />
             </button>
             <img src={previewImage} className="max-w-full max-h-full rounded shadow-2xl" alt="Preview" />
         </div>
      )}

    </div>
  );
};

export default ImageMerger;

import React, { useState, useEffect } from 'react';
import { 
    Images, 
    Trash2, 
    Download, 
    Maximize2, 
    Search, 
    Filter, 
    X, 
    Calendar, 
    Sparkles, 
    Image as ImageIcon,
    Video,
    ZoomIn,
    RotateCcw,
    Zap,
    ArrowUpCircle,
    CheckCircle,
    ChevronLeft,
    ChevronRight,
    Loader2,
    Grid,
    Layers,
    Star,
    SplitSquareHorizontal,
    Check,
    ArrowLeftRight
} from 'lucide-react';
import { HistoryItem, FeatureMode } from '../types';
import { upscaleImage } from '../services/huggingfaceService';

// Helper to flatten history items into individual images
interface GalleryItem {
    id: string; // Unique ID composed of historyId-index
    historyId: string;
    url: string;
    prompt: string;
    mode: FeatureMode;
    timestamp: number;
    type: 'image' | 'video';
}

interface GalleryProps {
    onNavigate?: (mode: FeatureMode) => void;
}

const ITEMS_PER_PAGE = 24; // Keeps grid dense and responsive

const Gallery: React.FC<GalleryProps> = ({ onNavigate }) => {
    const [galleryItems, setGalleryItems] = useState<GalleryItem[]>([]);
    const [filterMode, setFilterMode] = useState<FeatureMode | 'all' | 'favorites'>('all');
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedItem, setSelectedItem] = useState<GalleryItem | null>(null);
    const [currentPage, setCurrentPage] = useState(1);
    const [favorites, setFavorites] = useState<Set<string>>(new Set());

    // Upscaling States
    const [isUpscaling, setIsUpscaling] = useState(false);
    const [upscaledUrl, setUpscaledUrl] = useState<string | null>(null);
    const [upscaleError, setUpscaleError] = useState<string | null>(null);

    // Comparison States
    const [isSelectionMode, setIsSelectionMode] = useState(false);
    const [selectedForCompare, setSelectedForCompare] = useState<GalleryItem[]>([]);
    const [showCompareModal, setShowCompareModal] = useState(false);
    const [compareSliderPos, setCompareSliderPos] = useState(50);

    // Reset upscale state when selected item changes
    useEffect(() => {
        setUpscaledUrl(null);
        setUpscaleError(null);
        setIsUpscaling(false);
    }, [selectedItem]);

    // Reset pagination when filter or search changes
    useEffect(() => {
        setCurrentPage(1);
    }, [filterMode, searchTerm]);

    // Load Favorites
    useEffect(() => {
        try {
            const savedFavs = localStorage.getItem('andri_ai_favorites');
            if (savedFavs) {
                setFavorites(new Set(JSON.parse(savedFavs)));
            }
        } catch (e) {
            console.error("Failed to load favorites", e);
        }
    }, []);

    // Load and flatten history
    useEffect(() => {
        try {
            const savedHistory = localStorage.getItem('andri_ai_history');
            if (savedHistory) {
                const parsed: HistoryItem[] = JSON.parse(savedHistory);

                const flattened: GalleryItem[] = [];
                parsed.forEach(item => {
                    item.results.forEach((res, idx) => {
                        // Check if it's video or image based on URL/Base64 or feature type
                        const isVideo = item.type === 'video' || res.includes('data:video') || res.includes('.mp4');

                        flattened.push({
                            id: `${item.id}-${idx}`,
                            historyId: item.id,
                            url: res,
                            prompt: item.prompt,
                            mode: item.mode,
                            timestamp: item.timestamp,
                            type: isVideo ? 'video' : 'image'
                        });
                    });
                });

                // Sort by newest
                flattened.sort((a, b) => b.timestamp - a.timestamp);
                setGalleryItems(flattened);
            }
        } catch (e) {
            console.error("Failed to load gallery", e);
        }
    }, []);

    const toggleFavorite = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        const newFavs = new Set(favorites);
        if (newFavs.has(id)) {
            newFavs.delete(id);
        } else {
            newFavs.add(id);
        }
        setFavorites(newFavs);
        localStorage.setItem('andri_ai_favorites', JSON.stringify(Array.from(newFavs)));
    };

    const handleDelete = (itemId: string, historyId: string) => {
        if (!confirm("Hapus gambar ini dari galeri?")) return;

        // 1. Remove from local state
        const newGallery = galleryItems.filter(i => i.id !== itemId);
        setGalleryItems(newGallery);

        // 2. Remove from favorites if exists
        if (favorites.has(itemId)) {
            const newFavs = new Set(favorites);
            newFavs.delete(itemId);
            setFavorites(newFavs);
            localStorage.setItem('andri_ai_favorites', JSON.stringify(Array.from(newFavs)));
        }

        // 3. Update localStorage history
        try {
            const savedHistory = localStorage.getItem('andri_ai_history');
            if (savedHistory) {
                let parsed: HistoryItem[] = JSON.parse(savedHistory);

                // Find the history item
                const targetHistoryIndex = parsed.findIndex(h => h.id === historyId);
                if (targetHistoryIndex !== -1) {
                    const target = parsed[targetHistoryIndex];

                    // Filter out the specific result URL
                    const urlToRemove = galleryItems.find(g => g.id === itemId)?.url;
                    target.results = target.results.filter(r => r !== urlToRemove);

                    // If no results left, remove the history item entirely
                    if (target.results.length === 0) {
                        parsed = parsed.filter(h => h.id !== historyId);
                    } else {
                        parsed[targetHistoryIndex] = target;
                    }

                    localStorage.setItem('andri_ai_history', JSON.stringify(parsed));
                }
            }
        } catch (e) {
            console.error("Failed to delete", e);
        }

        if (selectedItem?.id === itemId) setSelectedItem(null);
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleUpscale = async () => {
        if (!selectedItem || selectedItem.type === 'video') return;

        setIsUpscaling(true);
        setUpscaleError(null);

        try {
            // Convert current image URL to Blob
            const response = await fetch(selectedItem.url);
            const blob = await response.blob();

            // Call Service
            const resultUrl = await upscaleImage(blob);
            setUpscaledUrl(resultUrl);
        } catch (err: any) {
            console.error("Upscale failed", err);
            setUpscaleError(err.message || "Gagal melakukan upscale.");
        } finally {
            setIsUpscaling(false);
        }
    };

    const handlePageChange = (newPage: number) => {
        setCurrentPage(newPage);
        // Smooth scroll to top of gallery
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    // --- COMPARISON LOGIC ---
    const toggleSelectionMode = () => {
        setIsSelectionMode(!isSelectionMode);
        setSelectedForCompare([]); // Reset selection when toggling
    };

    const handleSelectForCompare = (item: GalleryItem) => {
        if (item.type === 'video') return; // Cannot compare videos yet

        if (selectedForCompare.find(i => i.id === item.id)) {
            // Deselect
            setSelectedForCompare(prev => prev.filter(i => i.id !== item.id));
        } else {
            // Select (Max 2)
            if (selectedForCompare.length < 2) {
                setSelectedForCompare(prev => [...prev, item]);
            } else {
                // Replace the second one if 2 already selected (FIFO like logic or just block? Let's replace the last one)
                setSelectedForCompare(prev => [prev[0], item]);
            }
        }
    };

    const startComparison = () => {
        if (selectedForCompare.length === 2) {
            setShowCompareModal(true);
            setCompareSliderPos(50);
        }
    };

    // Filter Logic
    const filteredItems = galleryItems.filter(item => {
        const matchesSearch = item.prompt.toLowerCase().includes(searchTerm.toLowerCase());

        if (filterMode === 'favorites') {
            return favorites.has(item.id) && matchesSearch;
        }

        const matchesMode = filterMode === 'all' || item.mode === filterMode;
        return matchesMode && matchesSearch;
    });

    // Pagination Logic
    const totalPages = Math.ceil(filteredItems.length / ITEMS_PER_PAGE);
    const paginatedItems = filteredItems.slice(
        (currentPage - 1) * ITEMS_PER_PAGE, 
        currentPage * ITEMS_PER_PAGE
    );

    // Unique modes for filter dropdown
    const availableModes = Array.from(new Set(galleryItems.map(i => i.mode)));

    return (
        <div className="max-w-7xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500 min-h-[80vh]">

            {/* --- HEADER SECTION --- */}
            <div className="bg-white/80 dark:bg-black/40 backdrop-blur-xl border border-slate-200 dark:border-white/10 rounded-3xl p-6 md:p-8 mb-8 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

                <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 relative z-10">
                    <div>
                        <div className="flex items-center gap-3 mb-2">
                            <div className="p-2.5 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl shadow-lg shadow-emerald-500/20">
                                <Images className="text-white" size={24} />
                            </div>
                            <h2 className="text-3xl font-bold text-slate-800 dark:text-white tracking-tight">
                                Galeri Saya
                            </h2>
                        </div>
                        <p className="text-slate-500 dark:text-slate-400 text-lg font-light ml-1">
                            Koleksi masterpiece AI yang telah Anda buat.
                        </p>
                    </div>

                    <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">

                         {/* Compare Button Toggle */}
                         <button 
                            onClick={toggleSelectionMode}
                            className={`flex items-center justify-center gap-2 px-4 py-3.5 rounded-2xl font-bold transition-all border ${
                                isSelectionMode 
                                ? 'bg-indigo-500 text-white border-indigo-600 shadow-indigo-500/20 shadow-lg' 
                                : 'bg-slate-100/50 dark:bg-white/5 border-slate-200 dark:border-white/10 text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-white/10'
                            }`}
                        >
                            <SplitSquareHorizontal size={20} />
                            <span className="hidden sm:inline">{isSelectionMode ? 'Batal Compare' : 'Compare'}</span>
                        </button>

                        {/* Search Bar */}
                        <div className="relative group flex-1 sm:flex-none">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-emerald-500 transition-colors" size={20} />
                            <input 
                                type="text" 
                                placeholder="Cari prompt / hasil..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="w-full sm:w-60 pl-12 pr-10 py-3.5 bg-slate-100/50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl focus:border-emerald-500 focus:bg-white dark:focus:bg-black/50 outline-none text-sm transition-all shadow-inner text-slate-900 dark:text-white placeholder:text-slate-500 dark:placeholder:text-slate-500"
                            />
                            {searchTerm && (
                                <button 
                                    onClick={() => setSearchTerm('')}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-red-500 transition-colors p-1 rounded-full hover:bg-slate-200 dark:hover:bg-white/10"
                                >
                                    <X size={16} />
                                </button>
                            )}
                        </div>

                        {/* Filter Dropdown */}
                        <div className="relative group flex-1 sm:flex-none">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 group-focus-within:text-emerald-500 transition-colors"><Filter size={20} /></div>
                            <select 
                                value={filterMode}
                                onChange={(e) => setFilterMode(e.target.value as FeatureMode | 'all' | 'favorites')}
                                className="w-full sm:w-48 pl-12 pr-10 py-3.5 bg-slate-100/50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl focus:border-emerald-500 focus:bg-white dark:focus:bg-black/50 outline-none appearance-none cursor-pointer text-sm font-medium capitalize shadow-inner text-slate-900 dark:text-white"
                            >
                                <option value="all">Semua</option>
                                <option value="favorites" className="font-bold text-amber-500">⭐ Favorit</option>
                                {availableModes.map(mode => (
                                    <option key={mode} value={mode}>{mode}</option>
                                ))}
                            </select>
                            <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                                 <ChevronLeft size={16} className="-rotate-90" />
                            </div>
                        </div>
                    </div>
                </div>

                {/* --- STATS BAR INFO --- */}
                {filteredItems.length > 0 && (
                    <div className="mt-6 pt-6 border-t border-slate-200 dark:border-white/5 flex flex-wrap items-center justify-between gap-4">
                        <div className="flex flex-wrap items-center gap-4 text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                            <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 dark:bg-white/5 rounded-lg border border-slate-200 dark:border-white/5">
                                <Layers size={14} className="text-emerald-500" />
                                <span>Total: <span className="text-slate-800 dark:text-white">{filteredItems.length}</span></span>
                            </div>
                            <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 dark:bg-white/5 rounded-lg border border-slate-200 dark:border-white/5">
                                <CheckCircle size={14} className="text-amber-500" />
                                <span>Page: <span className="text-slate-800 dark:text-white">{currentPage}</span> / {totalPages}</span>
                            </div>
                        </div>

                        {/* Compare Action Hint */}
                        {isSelectionMode && (
                             <div className="flex items-center gap-3 animate-in fade-in slide-in-from-right-4">
                                <span className="text-sm font-medium text-slate-600 dark:text-slate-300">
                                    Pilih 2 gambar untuk dibandingkan:
                                </span>
                                <div className="flex items-center gap-1">
                                    {selectedForCompare.map((_, i) => (
                                        <div key={i} className="w-2.5 h-2.5 rounded-full bg-indigo-500 animate-pulse"></div>
                                    ))}
                                    {[...Array(2 - selectedForCompare.length)].map((_, i) => (
                                        <div key={i} className="w-2.5 h-2.5 rounded-full bg-slate-300 dark:bg-white/10"></div>
                                    ))}
                                </div>
                                <button 
                                    onClick={startComparison}
                                    disabled={selectedForCompare.length !== 2}
                                    className="ml-2 px-4 py-2 bg-indigo-500 hover:bg-indigo-600 disabled:bg-slate-300 disabled:cursor-not-allowed text-white text-xs font-bold rounded-lg transition-all shadow-lg shadow-indigo-500/20"
                                >
                                    Mulai Bandingkan
                                </button>
                             </div>
                        )}
                    </div>
                )}
            </div>

            {/* --- GRID CONTENT --- */}
            {filteredItems.length === 0 ? (
                <div className="text-center py-24 bg-white/50 dark:bg-black/20 backdrop-blur-md rounded-[2.5rem] border border-dashed border-slate-300 dark:border-white/10 animate-in fade-in zoom-in duration-300 shadow-xl">
                    <div className="w-28 h-28 bg-gradient-to-br from-slate-100 to-slate-200 dark:from-white/5 dark:to-white/10 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                        <ImageIcon className="text-slate-400 opacity-50" size={48} />
                    </div>
                    <h3 className="text-2xl font-bold text-slate-800 dark:text-white mb-3">Belum ada karya ditemukan</h3>
                    <p className="text-slate-500 dark:text-slate-400 max-w-md mx-auto leading-relaxed">
                        {filterMode === 'favorites' 
                           ? "Anda belum menandai karya apapun sebagai favorit." 
                           : (searchTerm ? `Tidak ada hasil untuk pencarian "${searchTerm}"` : "Galeri Anda masih kosong. Mulai buat gambar menakjubkan dengan AI sekarang.")
                        }
                    </p>

                    {searchTerm || filterMode !== 'all' ? (
                        <button 
                            onClick={() => { setSearchTerm(''); setFilterMode('all'); }}
                            className="mt-8 px-6 py-2 bg-slate-200 dark:bg-white/10 hover:bg-slate-300 dark:hover:bg-white/20 text-slate-700 dark:text-slate-300 font-bold rounded-full transition-all text-sm flex items-center gap-2 mx-auto"
                        >
                            <RotateCcw size={14} /> Reset Filter
                        </button>
                    ) : (
                        onNavigate && (
                            <button 
                                onClick={() => onNavigate('imagine')}
                                className="mt-8 px-8 py-4 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-400 hover:to-teal-500 text-white font-bold rounded-full transition-all shadow-xl shadow-emerald-500/20 hover:scale-105 hover:-translate-y-1 flex items-center gap-2 mx-auto"
                            >
                                <Zap size={20} /> Mulai Berkarya
                            </button>
                        )
                    )}
                </div>
            ) : (
                <>
                    {/* Modern Grid Layout */}
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 sm:gap-6">
                        {paginatedItems.map((item) => {
                            const isSelected = selectedForCompare.some(i => i.id === item.id);

                            return (
                                <div 
                                    key={item.id} 
                                    className={`group relative aspect-square bg-white dark:bg-[#1a1a1c] rounded-2xl overflow-hidden shadow-lg border cursor-pointer animate-in fade-in duration-700 transition-all 
                                        ${isSelectionMode 
                                            ? (isSelected 
                                                ? 'ring-4 ring-indigo-500 border-transparent shadow-indigo-500/30 transform scale-95' 
                                                : 'border-slate-200 dark:border-white/5 opacity-80 hover:opacity-100 hover:scale-105')
                                            : 'border-slate-200 dark:border-white/5 hover:border-emerald-500/50 hover:shadow-2xl hover:shadow-emerald-500/10 hover:-translate-y-1.5'
                                        }
                                    `}
                                    onClick={() => isSelectionMode ? handleSelectForCompare(item) : setSelectedItem(item)}
                                >
                                    {/* Selection Badge */}
                                    {isSelectionMode && isSelected && (
                                        <div className="absolute top-2 right-2 z-20 w-6 h-6 bg-indigo-500 text-white rounded-full flex items-center justify-center shadow-lg animate-in zoom-in">
                                            <Check size={14} strokeWidth={3} />
                                        </div>
                                    )}

                                    {/* Media Content */}
                                    {item.type === 'video' ? (
                                        <video src={item.url} className="w-full h-full object-cover" muted />
                                    ) : (
                                        <img 
                                            src={item.url} 
                                            alt={item.prompt} 
                                            loading="lazy"
                                            className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" 
                                        />
                                    )}

                                    {/* Overlay Gradient & Quick Actions (Hidden in Selection Mode) */}
                                    {!isSelectionMode && (
                                        <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-4">

                                            {/* Action Buttons */}
                                            <div className="flex gap-2 justify-end mb-auto pt-1 transform -translate-y-4 group-hover:translate-y-0 transition-transform duration-300">
                                                <button 
                                                    onClick={(e) => toggleFavorite(e, item.id)}
                                                    className={`p-2 backdrop-blur-md rounded-xl transition-all shadow-lg border border-white/10 ${
                                                        favorites.has(item.id) 
                                                        ? 'bg-amber-500 text-white' 
                                                        : 'bg-white/10 text-white hover:bg-amber-500'
                                                    }`}
                                                    title="Favorite"
                                                >
                                                    <Star size={16} fill={favorites.has(item.id) ? "currentColor" : "none"} />
                                                </button>

                                                {item.type !== 'video' && (
                                                    <button 
                                                        onClick={(e) => { e.stopPropagation(); setSelectedItem(item); }}
                                                        className="p-2 bg-white/10 hover:bg-indigo-500 backdrop-blur-md rounded-xl text-white transition-all shadow-lg border border-white/10"
                                                        title="Upscale / Enhance"
                                                    >
                                                        <ArrowUpCircle size={16} />
                                                    </button>
                                                )}
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); handleDownload(item.url, `AndriAI-${item.id}.png`); }}
                                                    className="p-2 bg-white/10 hover:bg-emerald-500 backdrop-blur-md rounded-xl text-white transition-all shadow-lg border border-white/10"
                                                    title="Download"
                                                >
                                                    <Download size={16} />
                                                </button>
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); handleDelete(item.id, item.historyId); }}
                                                    className="p-2 bg-white/10 hover:bg-red-500 backdrop-blur-md rounded-xl text-white transition-all shadow-lg border border-white/10"
                                                    title="Delete"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>

                                            {/* Info Text */}
                                            <div className="transform translate-y-4 group-hover:translate-y-0 transition-transform duration-300 delay-75">
                                                <div className="flex items-center gap-2 mb-1.5">
                                                    <span className="text-[9px] font-bold bg-emerald-500/20 text-emerald-300 px-2 py-0.5 rounded border border-emerald-500/20 uppercase tracking-widest backdrop-blur-sm">
                                                        {item.mode}
                                                    </span>
                                                </div>
                                                <p className="text-[11px] text-slate-200 line-clamp-2 leading-relaxed font-medium">{item.prompt}</p>
                                            </div>
                                        </div>
                                    )}

                                    {/* Type Badge */}
                                    {item.type === 'video' && (
                                        <div className="absolute top-3 left-3 px-2.5 py-1 bg-black/60 backdrop-blur-md rounded-lg text-[10px] font-bold text-white flex items-center gap-1.5 border border-white/10">
                                            <Video size={12} className="text-pink-400" /> VIDEO
                                        </div>
                                    )}
                                </div>
                            )
                        })}
                    </div>

                    {/* Pagination Controls */}
                    {totalPages > 1 && (
                        <div className="mt-16 flex items-center justify-center">
                            <div className="flex items-center gap-4 bg-white dark:bg-black/40 backdrop-blur-md p-2 rounded-2xl shadow-xl border border-slate-200 dark:border-white/10">
                                <button
                                    onClick={() => handlePageChange(currentPage - 1)}
                                    disabled={currentPage === 1}
                                    className="p-3 rounded-xl hover:bg-slate-100 dark:hover:bg-white/10 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-slate-700 dark:text-white"
