                {/* 5. Additional Settings (Ratio, Models, etc) - Only for Image/Video */}
                {!isAudioMode && !isDownloaderMode && !isFaceSwap && !feature.id.includes('remove') && !feature.id.includes('upscale') && (
                     <div className="grid grid-cols-2 gap-4 mb-6 animate-in fade-in">
                        {/* Aspect Ratio */}
                        <div>
                             <label className="block text-xs font-bold text-slate-500 mb-2 uppercase">Rasio Aspek</label>
                             <div className="flex bg-slate-100 dark:bg-white/5 p-1 rounded-lg border border-slate-200 dark:border-white/5">
                                 {[
                                     { r: AspectRatio.SQUARE, icon: <Square size={14} />, label: '1:1' },
                                     { r: AspectRatio.PORTRAIT, icon: <RectangleVertical size={14} />, label: '9:16' },
                                     { r: AspectRatio.LANDSCAPE, icon: <RectangleHorizontal size={14} />, label: '16:9' },
                                 ].map((opt) => (
                                     <button
                                         key={opt.r}
                                         onClick={() => setRatio(opt.r)}
                                         className={`flex-1 py-2 rounded-md flex items-center justify-center gap-1.5 transition-all text-xs font-medium ${
                                             ratio === opt.r 
                                             ? 'bg-white dark:bg-emerald-600 text-emerald-600 dark:text-white shadow-sm' 
                                             : 'text-slate-500 hover:bg-white/50 dark:hover:bg-white/10'
                                         }`}
                                         title={opt.label}
                                     >
                                         {opt.icon} {opt.label}
                                     </button>
                                 ))}
                             </div>
                        </div>
                     </div>
                )}

                {/* 6. Main Action Button */}
                <button
                    onClick={isDownloaderMode ? handleDownloadUrl : handleGenerate}
                    disabled={loading || (isDownloaderMode && !downloadUrlInput)}
                    className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all transform active:scale-95 flex items-center justify-center gap-2 group relative overflow-hidden ${
                        loading 
                        ? 'bg-slate-700 cursor-not-allowed' 
                        : 'bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 shadow-emerald-500/25'
                    }`}
                >
                    {loading ? (
                       <>
                         <RefreshCw className="animate-spin" size={20} />
                         {isDownloaderMode ? `Memproses Video ${downloadProgress}%` : 
                          (feature.id === 'banana' && genProgress.total > 0 ? `Generating ${genProgress.current}/${genProgress.total}` : 'Sedang Memproses AI...')}
                       </>
                    ) : (
                       <>
                         {isDownloaderMode ? <FileDown size={20} /> : (isAudioMode ? <Play size={20} /> : <Wand2 size={20} />)}
