                    ) : generatedResults.length > 0 ? (
                        <div className={`grid gap-6 ${isAudioMode ? 'grid-cols-1' : (generatedResults.length === 1 ? 'grid-cols-1' : 'grid-cols-1 md:grid-cols-2')}`}>
                            {generatedResults.map((res, idx) => (
                                <div key={idx} className="group relative bg-white dark:bg-[#151517] rounded-2xl overflow-hidden shadow-xl border border-slate-200 dark:border-white/10 animate-in zoom-in-95 duration-500">

                                    {/* TTS Audio Player */}
                                    {isAudioMode ? (
                                        <div className="p-8 flex flex-col items-center justify-center min-h-[200px]">
                                            <div className="w-16 h-16 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-full flex items-center justify-center shadow-lg mb-6 animate-bounce-slow">
                                                <Music className="text-white" size={32} />
                                            </div>
                                            <audio controls src={res} className="w-full max-w-md" />
                                            <div className="mt-6 flex gap-4">
                                                <a 
                                                   href={res} 
                                                   download={`AndriAI-Voice-${Date.now()}.wav`}
                                                   className="flex items-center gap-2 px-6 py-2 bg-slate-800 hover:bg-black text-white rounded-full text-sm font-bold transition-all"
                                                >
                                                   <Download size={16} /> Download WAV
                                                </a>
                                            </div>
                                        </div>
                                    ) : (
                                    /* Image/Video Result */
                                        <>
                                            {isVideoMode ? (
                                                <video src={res} controls autoPlay loop className="w-full h-auto" />
                                            ) : (
                                                <img src={res} alt="Generated" className="w-full h-auto object-contain" />
                                            )}

                                            {/* Overlay Actions */}
                                            <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4 backdrop-blur-sm">
                                                <button 
                                                    onClick={() => {
                                                        const link = document.createElement('a');
                                                        link.href = res;
                                                        link.download = `AndriAI-${Date.now()}.${isVideoMode ? 'mp4' : 'png'}`;
                                                        link.click();
                                                    }}
                                                    className="p-3 bg-white text-black rounded-full hover:bg-emerald-400 hover:scale-110 transition-all shadow-lg"
                                                    title="Download"
                                                >
                                                    <Download size={20} />
                                                </button>
                                                {!isVideoMode && (
                                                    <button 
                                                        onClick={() => setPreviewImage(res)}
                                                        className="p-3 bg-white text-black rounded-full hover:bg-purple-400 hover:scale-110 transition-all shadow-lg"
                                                        title="Preview Fullscreen"
                                                    >
                                                        <Maximize2 size={20} />
                                                    </button>
                                                )}
                                            </div>
                                        </>
                                    )}
                                </div>
                            ))}
                        </div>
                    ) : downloadResult ? (
                         /* Downloader Result View */
                         <div className="flex flex-col items-center justify-center h-full animate-in zoom-in">
                            <div className="bg-white dark:bg-[#151517] p-6 rounded-3xl shadow-2xl border border-slate-200 dark:border-white/10 max-w-sm w-full">
                                <img src={downloadResult.thumbnail} alt="Thumb" className="w-full h-48 object-cover rounded-xl mb-4 shadow-md" />
                                <h4 className="font-bold text-lg text-slate-800 dark:text-white line-clamp-2 mb-2">{downloadResult.title}</h4>
                                <div className="flex justify-between text-sm text-slate-500 mb-6">
                                    <span>{downloadResult.format.toUpperCase()}</span>
                                    <span>{downloadResult.size}</span>
                                </div>
                                <a 
                                   href={downloadResult.downloadUrl}
                                   className="block w-full py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-bold text-center rounded-xl transition-all shadow-lg shadow-emerald-500/20"
                                >
                                    Download File
                                </a>
                            </div>
                         </div>
                    ) : (
                        /* Empty State */
                        <div className="h-full flex flex-col items-center justify-center text-center opacity-40 select-none">
                             <div className="w-32 h-32 bg-slate-200 dark:bg-white/5 rounded-full flex items-center justify-center mb-6">
                                {isAudioMode ? <AudioLines size={48} /> : <ImageIcon size={48} />}
                             </div>
                             <p className="text-xl font-medium">Hasil akan muncul disini</p>
                        </div>
                    )}
                </div>
            </div>
        </div>

      </div>

      {/* Prompt Library Modal */}
      {showPromptLib && (
         <PromptLibrary onSelect={(txt) => { setPrompt(txt); setShowPromptLib(false); }} onClose={() => setShowPromptLib(false)} />
      )}

      {/* Voice Clone Modal */}
      {showCloneModal && (
          <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in">
              <div className="bg-white dark:bg-[#1a1a1c] w-full max-w-md rounded-2xl shadow-2xl border border-slate-200 dark:border-white/10 overflow-hidden">
                  <div className="p-5 border-b border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-white/5 flex justify-between items-center">
                      <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
                          <UserPlus size={18} className="text-purple-500" /> Clone Suara Baru
                      </h3>
                      <button onClick={() => setShowCloneModal(false)} className="p-1 hover:bg-white/10 rounded-full">
                          <X size={18} className="text-slate-500" />
                      </button>
                  </div>
                  <div className="p-6 space-y-4">
                      <div className="space-y-2">
                          <label className="text-sm font-bold text-slate-600 dark:text-slate-400">Nama Suara</label>
                          <input 
                            type="text" 
                            value={cloneName}
                            onChange={(e) => setCloneName(e.target.value)}
                            className="w-full p-3 bg-slate-50 dark:bg-black/30 border border-slate-200 dark:border-white/10 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none"
                            placeholder="Contoh: Suara Sendiri"
                          />
                      </div>
                      <div className="space-y-2">
                          <label className="text-sm font-bold text-slate-600 dark:text-slate-400">Upload Sample (MP3/WAV)</label>
                          <div 
                             onClick={() => cloneFileInputRef.current?.click()}
                             className="border-2 border-dashed border-slate-300 dark:border-white/20 rounded-xl p-6 text-center cursor-pointer hover:bg-slate-50 dark:hover:bg-white/5 hover:border-purple-500 transition-colors"
                          >
                              {cloneFile ? (
                                  <div className="flex items-center justify-center gap-2 text-purple-500 font-bold">
                                      <FileAudio size={24} /> {cloneFile.name}
                                  </div>
                              ) : (
                                  <div className="flex flex-col items-center gap-2 text-slate-400">
                                      <UploadCloud size={24} />
                                      <span className="text-xs">Klik untuk upload file audio (min 10 detik)</span>
                                  </div>
                              )}
                          </div>
                          <input 
                            type="file" 
                            ref={cloneFileInputRef} 
                            onChange={handleCloneFileChange} 
                            accept="audio/*" 
                            className="hidden" 
                          />
                      </div>

                      {error && (
                        <div className="text-xs text-red-500 bg-red-50 dark:bg-red-900/10 p-2 rounded flex items-center gap-1">
                             <AlertCircle size={12} /> {error}
                        </div>
                      )}
                  </div>
                  <div className="p-5 border-t border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-white/5 flex justify-end">
                      <button 
                        onClick={handleCloneSubmit}
                        disabled={isCloning}
                        className="px-6 py-2.5 bg-purple-600 hover:bg-purple-500 text-white font-bold rounded-xl shadow-lg shadow-purple-500/20 disabled:opacity-50 flex items-center gap-2"
                      >
                          {isCloning ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                          {isCloning ? 'Memproses AI...' : 'Clone Suara'}
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Fullscreen Preview */}
      {previewImage && (
         <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4">
             <button onClick={() => setPreviewImage(null)} className="absolute top-6 right-6 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white">
                 <X size={24} />
             </button>
             <img src={previewImage} className="max-w-full max-h-full rounded shadow-2xl" alt="Preview" />
         </div>
      )}

    </div>
  );
};

export default ImageMerger;

import React, { useState, useEffect } from 'react';
import { 
    Images, 
    Trash2, 
    Download, 
    Maximize2, 
    Search, 
    Filter, 
    X, 
    Calendar, 
    Sparkles, 
    Image as ImageIcon,
    Video,
    ZoomIn,
    RotateCcw,
    Zap,
    ArrowUpCircle,
    CheckCircle,
    ChevronLeft,
    ChevronRight,
    Loader2,
    Grid,
    Layers,
    Star,
    SplitSquareHorizontal,
    Check,
    ArrowLeftRight,
    Columns
} from 'lucide-react';
import { HistoryItem, FeatureMode } from '../types';
import { upscaleImage } from '../services/huggingfaceService';

// Helper to flatten history items into individual images
interface GalleryItem {
    id: string; // Unique ID composed of historyId-index
    historyId: string;
    url: string;
    prompt: string;
    mode: FeatureMode;
    timestamp: number;
    type: 'image' | 'video';
}

interface GalleryProps {
    onNavigate?: (mode: FeatureMode) => void;
}

const ITEMS_PER_PAGE = 24; // Keeps grid dense and responsive

const Gallery: React.FC<GalleryProps> = ({ onNavigate }) => {
    const [galleryItems, setGalleryItems] = useState<GalleryItem[]>([]);
    const [filterMode, setFilterMode] = useState<FeatureMode | 'all' | 'favorites'>('all');
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedItem, setSelectedItem] = useState<GalleryItem | null>(null);
    const [currentPage, setCurrentPage] = useState(1);
    const [favorites, setFavorites] = useState<Set<string>>(new Set());

    // Upscaling States
    const [isUpscaling, setIsUpscaling] = useState(false);
    const [upscaledUrl, setUpscaledUrl] = useState<string | null>(null);
    const [upscaleError, setUpscaleError] = useState<string | null>(null);

    // Comparison States
    const [isSelectionMode, setIsSelectionMode] = useState(false);
    const [selectedForCompare, setSelectedForCompare] = useState<GalleryItem[]>([]);
    const [showCompareModal, setShowCompareModal] = useState(false);
    const [compareSliderPos, setCompareSliderPos] = useState(50);
    const [compareMode, setCompareMode] = useState<'slider' | 'split'>('slider');

    // Reset upscale state when selected item changes
    useEffect(() => {
        setUpscaledUrl(null);
        setUpscaleError(null);
        setIsUpscaling(false);
    }, [selectedItem]);

    // Reset pagination when filter or search changes
    useEffect(() => {
        setCurrentPage(1);
    }, [filterMode, searchTerm]);

    // Load Favorites
    useEffect(() => {
        try {
            const savedFavs = localStorage.getItem('andri_ai_favorites');
            if (savedFavs) {
                setFavorites(new Set(JSON.parse(savedFavs)));
            }
        } catch (e) {
            console.error("Failed to load favorites", e);
        }
    }, []);

    // Load and flatten history
    useEffect(() => {
        try {
            const savedHistory = localStorage.getItem('andri_ai_history');
            if (savedHistory) {
                const parsed: HistoryItem[] = JSON.parse(savedHistory);

                const flattened: GalleryItem[] = [];
                parsed.forEach(item => {
                    item.results.forEach((res, idx) => {
                        // Check if it's video or image based on URL/Base64 or feature type
                        const isVideo = item.type === 'video' || res.includes('data:video') || res.includes('.mp4');

                        flattened.push({
                            id: `${item.id}-${idx}`,
                            historyId: item.id,
                            url: res,
                            prompt: item.prompt,
                            mode: item.mode,
                            timestamp: item.timestamp,
                            type: isVideo ? 'video' : 'image'
                        });
                    });
                });

                // Sort by newest
                flattened.sort((a, b) => b.timestamp - a.timestamp);
                setGalleryItems(flattened);
            }
        } catch (e) {
            console.error("Failed to load gallery", e);
        }
    }, []);

    const toggleFavorite = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        const newFavs = new Set(favorites);
        if (newFavs.has(id)) {
            newFavs.delete(id);
        } else {
            newFavs.add(id);
        }
        setFavorites(newFavs);
        localStorage.setItem('andri_ai_favorites', JSON.stringify(Array.from(newFavs)));
    };

    const handleDelete = (itemId: string, historyId: string) => {
        if (!confirm("Hapus gambar ini dari galeri?")) return;

        // 1. Remove from local state
        const newGallery = galleryItems.filter(i => i.id !== itemId);
        setGalleryItems(newGallery);

        // 2. Remove from favorites if exists
        if (favorites.has(itemId)) {
            const newFavs = new Set(favorites);
            newFavs.delete(itemId);
            setFavorites(newFavs);
            localStorage.setItem('andri_ai_favorites', JSON.stringify(Array.from(newFavs)));
        }

        // 3. Update localStorage history
        try {
            const savedHistory = localStorage.getItem('andri_ai_history');
            if (savedHistory) {
                let parsed: HistoryItem[] = JSON.parse(savedHistory);

                // Find the history item
                const targetHistoryIndex = parsed.findIndex(h => h.id === historyId);
                if (targetHistoryIndex !== -1) {
                    const target = parsed[targetHistoryIndex];

                    // Filter out the specific result URL
                    const urlToRemove = galleryItems.find(g => g.id === itemId)?.url;
                    target.results = target.results.filter(r => r !== urlToRemove);

                    // If no results left, remove the history item entirely
                    if (target.results.length === 0) {
                        parsed = parsed.filter(h => h.id !== historyId);
                    } else {
                        parsed[targetHistoryIndex] = target;
                    }

                    localStorage.setItem('andri_ai_history', JSON.stringify(parsed));
                }
            }
        } catch (e) {
            console.error("Failed to delete", e);
        }

        if (selectedItem?.id === itemId) setSelectedItem(null);
    };

    const handleDownload = (url: string, filename: string) => {
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleUpscale = async () => {
        if (!selectedItem || selectedItem.type === 'video') return;

        setIsUpscaling(true);
        setUpscaleError(null);

        try {
            // Convert current image URL to Blob
            const response = await fetch(selectedItem.url);
            const blob = await response.blob();

            // Call Service
            const resultUrl = await upscaleImage(blob);
            setUpscaledUrl(resultUrl);
        } catch (err: any) {
            console.error("Upscale failed", err);
            setUpscaleError(err.message || "Gagal melakukan upscale.");
        } finally {
            setIsUpscaling(false);
        }
    };

    const handlePageChange = (newPage: number) => {
        setCurrentPage(newPage);
        // Smooth scroll to top of gallery
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    // --- COMPARISON LOGIC ---
    const toggleSelectionMode = () => {
        setIsSelectionMode(!isSelectionMode);
        setSelectedForCompare([]); // Reset selection when toggling
    };

    const handleSelectForCompare = (item: GalleryItem) => {
        if (item.type === 'video') return; // Cannot compare videos yet

        if (selectedForCompare.find(i => i.id === item.id)) {
            // Deselect
            setSelectedForCompare(prev => prev.filter(i => i.id !== item.id));
        } else {
            // Select (Max 2)
            if (selectedForCompare.length < 2) {
                setSelectedForCompare(prev => [...prev, item]);
            } else {
                // Replace the second one if 2 already selected (FIFO like logic or just block? Let's replace the last one)
                setSelectedForCompare(prev => [prev[0], item]);
            }
        }
    };

    const startComparison = () => {
        if (selectedForCompare.length === 2) {
            setShowCompareModal(true);
            setCompareSliderPos(50);
            setCompareMode('slider');
        }
    };

    // Filter Logic
    const filteredItems = galleryItems.filter(item => {
        const matchesSearch = item.prompt.toLowerCase().includes(searchTerm.toLowerCase());

        if (filterMode === 'favorites') {
            return favorites.has(item.id) && matchesSearch;
        }

        const matchesMode = filterMode === 'all' || item.mode === filterMode;
        return matchesMode && matchesSearch;
    });

    // Pagination Logic
    const totalPages = Math.ceil(filteredItems.length / ITEMS_PER_PAGE);
    const paginatedItems = filteredItems.slice(
        (currentPage - 1) * ITEMS_PER_PAGE, 
        currentPage * ITEMS_PER_PAGE
    );

    // Unique modes for filter dropdown
    const availableModes = Array.from(new Set(galleryItems.map(i => i.mode)));

    return (
        <div className="max-w-7xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500 min-h-[80vh]">

            {/* --- HEADER SECTION --- */}
            <div className="bg-white/80 dark:bg-black/40 backdrop-blur-xl border border-slate-200 dark:border-white/10 rounded-3xl p-6 md:p-8 mb-8 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

                <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 relative z-10">
                    <div>
                        <div className="flex items-center gap-3 mb-2">
                            <div className="p-2.5 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl shadow-lg shadow-emerald-500/20">
                                <Images className="text-white" size={24} />
                            </div>
                            <h2 className="text-3xl font-bold text-slate-800 dark:text-white tracking-tight">
                                Galeri Saya
                            </h2>
                        </div>
                        <p className="text-slate-500 dark:text-slate-400 text-lg font-light ml-1">
                            Koleksi masterpiece AI yang telah Anda buat.
                        </p>
                    </div>

                    <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">

                         {/* Compare Button Toggle */}
                         <button 
                            onClick={toggleSelectionMode}
                            className={`flex items-center justify-center gap-2 px-4 py-3.5 rounded-2xl font-bold transition-all border ${
                                isSelectionMode 
                                ? 'bg-indigo-500 text-white border-indigo-600 shadow-indigo-500/20 shadow-lg' 
                                : 'bg-slate-100/50 dark:bg-white/5 border-slate-200 dark:border-white/10 text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-white/10'
                            }`}
                        >
                            <SplitSquareHorizontal size={20} />
                            <span className="hidden sm:inline">{isSelectionMode ? 'Batal Compare' : 'Compare'}</span>
                        </button>

                        {/* Search Bar */}
                        <div className="relative group flex-1 sm:flex-none">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-emerald-500 transition-colors" size={20} />
                            <input 
                                type="text" 
                                placeholder="Cari prompt / hasil..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="w-full sm:w-60 pl-12 pr-10 py-3.5 bg-slate-100/50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl focus:border-emerald-500 focus:bg-white dark:focus:bg-black/50 outline-none text-sm transition-all shadow-inner text-slate-900 dark:text-white placeholder:text-slate-500 dark:placeholder:text-slate-500"
                            />
                            {searchTerm && (
                                <button 
                                    onClick={() => setSearchTerm('')}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-red-500 transition-colors p-1 rounded-full hover:bg-slate-200 dark:hover:bg-white/10"
                                >
                                    <X size={16} />
                                </button>
                            )}
                        </div>

                        {/* Filter Dropdown */}
                        <div className="relative group flex-1 sm:flex-none">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500 group-focus-within:text-emerald-500 transition-colors"><Filter size={20} /></div>
                            <select 
                                value={filterMode}
                                onChange={(e) => setFilterMode(e.target.value as FeatureMode | 'all' | 'favorites')}
                                className="w-full sm:w-48 pl-12 pr-10 py-3.5 bg-slate-100/50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl focus:border-emerald-500 focus:bg-white dark:focus:bg-black/50 outline-none appearance-none cursor-pointer text-sm font-medium capitalize shadow-inner text-slate-900 dark:text-white"
                            >
                                <option value="all">Semua</option>
                                <option value="favorites" className="font-bold text-amber-500">⭐ Favorit</option>
                                {availableModes.map(mode => (
                                    <option key={mode} value={mode}>{mode}</option>
                                ))}
                            </select>
                            <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                                 <ChevronLeft size={16} className="-rotate-90" />
                            </div>
                        </div>
                    </div>
                </div>

                {/* --- STATS BAR INFO --- */}
                {filteredItems.length > 0 && (
                    <div className="mt-6 pt-6 border-t border-slate-200 dark:border-white/5 flex flex-wrap items-center justify-between gap-4">
                        <div className="flex flex-wrap items-center gap-4 text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                            <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 dark:bg-white/5 rounded-lg border border-slate-200 dark:border-white/5">
                                <Layers size={14} className="text-emerald-500" />
                                <span>Total: <span className="text-slate-800 dark:text-white">{filteredItems.length}</span></span>
                            </div>
                            <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-100 dark:bg-white/5 rounded-lg border border-slate-200 dark:border-white/5">
                                <CheckCircle size={14} className="text-amber-500" />
                                <span>Page: <span className="text-slate-800 dark:text-white">{currentPage}</span> / {totalPages}</span>
                            </div>
                        </div>

                        {/* Compare Action Hint */}
                        {isSelectionMode && (
                             <div className="flex items-center gap-3 animate-in fade-in slide-in-from-right-4">
                                <span className="text-sm font-medium text-slate-600 dark:text-slate-300">
                                    Pilih 2 gambar untuk dibandingkan:
                                </span>
                                <div className="flex items-center gap-1">
                                    {selectedForCompare.map((_, i) => (
                                        <div key={i} className="w-2.5 h-2.5 rounded-full bg-indigo-500 animate-pulse"></div>
                                    ))}
                                    {[...Array(2 - selectedForCompare.length)].map((_, i) => (
                                        <div key={i} className="w-2.5 h-2.5 rounded-full bg-slate-300 dark:bg-white/10"></div>
                                    ))}
                                </div>
                                <button 
                                    onClick={startComparison}
                                    disabled={selectedForCompare.length !== 2}
                                    className="ml-2 px-4 py-2 bg-indigo-500 hover:bg-indigo-600 disabled:bg-slate-300 disabled:cursor-not-allowed text-white text-xs font-bold rounded-lg transition-all shadow-lg shadow-indigo-500/20"
                                >
                                    Mulai Bandingkan
                                </button>
                             </div>
                        )}
                    </div>
                )}
            </div>

            {/* --- GRID CONTENT --- */}
            {filteredItems.length === 0 ? (
