            )}

            {/* Lightbox Modal (Full Screen View) */}
            {selectedItem && !isSelectionMode && (
                <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-2xl flex items-center justify-center animate-in fade-in duration-300 p-4 sm:p-6">
                    <button 
                        onClick={() => setSelectedItem(null)}
                        className="absolute top-4 right-4 sm:top-6 sm:right-6 p-3 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors z-[110] border border-white/10"
                    >
                        <X size={24} />
                    </button>

                    <div className="flex flex-col lg:flex-row w-full h-full max-w-[90vw] max-h-[90vh] overflow-hidden rounded-[2.5rem] bg-[#0c0c0e] border border-white/10 shadow-2xl relative">

                        {/* Image Viewer Area */}
                        <div className="flex-1 bg-black/50 relative flex items-center justify-center p-4 lg:p-10 bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')]">
