                                <video src={selectedItem.url} controls autoPlay className="max-w-full max-h-full rounded-2xl shadow-2xl border border-white/5" />
                             ) : (
                                <img 
                                    src={upscaledUrl || selectedItem.url} 
                                    alt="Full View" 
                                    className="max-w-full max-h-full object-contain rounded-lg shadow-2xl transition-all duration-300 select-none drop-shadow-[0_0_50px_rgba(0,0,0,0.5)]" 
                                />
                             )}

                             {/* Upscale Indicator */}
                             {upscaledUrl && (
                                 <div className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-emerald-500/90 backdrop-blur text-white px-6 py-2.5 rounded-full font-bold shadow-xl flex items-center gap-2 animate-in slide-in-from-bottom-4 border border-emerald-400/50">
                                     <Sparkles size={18} className="animate-pulse" /> AI Enhanced (4K)
                                 </div>
                             )}
                        </div>

                        {/* Sidebar Details */}
