                                    </div>
                                </div>

                                {upscaleError && (
                                    <div className="p-4 bg-red-50 dark:bg-red-900/10 text-red-600 dark:text-red-400 text-xs rounded-2xl border border-red-100 dark:border-red-900/20 flex items-center gap-2 font-medium">
