                                {selectedItem.type !== 'video' && !upscaledUrl && (
                                    <button 
                                        onClick={handleUpscale}
                                        disabled={isUpscaling}
                                        className="w-full py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 disabled:from-slate-700 disabled:to-slate-800 text-white font-bold rounded-2xl flex items-center justify-center gap-3 transition-all shadow-lg shadow-indigo-500/20 active:scale-95 group"
