                                            <>
                                                <ArrowUpCircle size={20} className="group-hover:animate-bounce" /> Upscale to 4K (AI)
                                            </>
                                        )}
                                    </button>
                                )}

                                <div className="grid grid-cols-2 gap-4">
                                    <button 
                                        onClick={() => handleDownload(upscaledUrl || selectedItem.url, `AndriAI-${selectedItem.id}${upscaledUrl ? '-HD' : ''}.png`)}
