                                </div>
                            </div>
                        </div>

                    </div>
                </div>
            )}

            {/* COMPARISON MODAL */}
            {showCompareModal && selectedForCompare.length === 2 && (
                <div className="fixed inset-0 z-[120] bg-black/95 backdrop-blur-xl flex items-center justify-center animate-in fade-in duration-300">
