                                <button 
                                    onClick={() => setCompareMode('slider')}
                                    className={`px-3 py-1 rounded-md text-xs font-bold transition-all ${compareMode === 'slider' ? 'bg-indigo-500 text-white shadow-lg' : 'text-slate-300 hover:bg-white/10'}`}
                                >
                                    Slider Blend
                                </button>
                                <button 
                                    onClick={() => setCompareMode('split')}
                                    className={`px-3 py-1 rounded-md text-xs font-bold transition-all ${compareMode === 'split' ? 'bg-indigo-500 text-white shadow-lg' : 'text-slate-300 hover:bg-white/10'}`}
                                >
                                    Side-by-Side
                                </button>
                            </div>

                            {/* Swap Button */}
                            <button 
                                onClick={() => setSelectedForCompare(prev => [prev[1], prev[0]])}
                                className="p-1.5 hover:bg-white/20 rounded-full transition-colors"
                                title="Swap Images"
                            >
                                <RotateCcw size={16} />
                            </button>
                        </div>

                        <div className="relative flex-1 w-full max-w-5xl rounded-2xl overflow-hidden border border-white/10 shadow-2xl bg-black/50 select-none">
                            {compareMode === 'slider' ? (
                                <>
                                    {/* Base Image (Right/After) */}
                                    {renderCompareMedia(selectedForCompare[1], "absolute inset-0 w-full h-full")}

                                    {/* Overlay Image (Left/Before) with Clip Path */}
                                    <div 
                                        className="absolute inset-0 w-full h-full bg-black/50"
                                        style={{ 
                                            clipPath: `inset(0 ${100 - compareSliderPos}% 0 0)` // Crop from right
                                        }}
                                    >
                                        {renderCompareMedia(selectedForCompare[0], "absolute inset-0 w-full h-full")}

                                        {/* Label for Left Image */}
                                        <div className="absolute top-4 left-4 bg-black/60 text-white text-xs font-bold px-3 py-1 rounded backdrop-blur-md border border-white/10">
                                            Awal / Kiri
                                        </div>
                                    </div>

                                    {/* Label for Right Image */}
                                     <div className="absolute top-4 right-4 bg-black/60 text-white text-xs font-bold px-3 py-1 rounded backdrop-blur-md border border-white/10">
                                        Akhir / Kanan
                                    </div>

                                    {/* Slider Handle Line */}
                                    <div 
                                        className="absolute top-0 bottom-0 w-0.5 bg-white cursor-ew-resize z-20 pointer-events-none drop-shadow-md"
                                        style={{ left: `${compareSliderPos}%` }}
                                    >
                                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-lg text-slate-800">
                                            <ArrowLeftRight size={18} />
                                        </div>
                                    </div>

                                    {/* Invisible Range Input for Interaction */}
                                    <input
                                        type="range"
                                        min="0"
                                        max="100"
                                        value={compareSliderPos}
                                        onChange={(e) => setCompareSliderPos(Number(e.target.value))}
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-ew-resize z-30"
                                    />
                                </>
                            ) : (
                                /* Side-by-Side Split View */
                                <div className="flex w-full h-full">
                                      <div className="flex-1 relative border-r border-white/10 bg-black/20 overflow-hidden">
                                          {renderCompareMedia(selectedForCompare[0], "absolute inset-0 w-full h-full")}
                                           <div className="absolute bottom-4 left-4 bg-black/60 text-white text-xs font-bold px-3 py-1 rounded backdrop-blur-md border border-white/10">
                                                Item 1
                                            </div>
                                      </div>
                                      <div className="flex-1 relative bg-black/20 overflow-hidden">
                                          {renderCompareMedia(selectedForCompare[1], "absolute inset-0 w-full h-full")}
                                           <div className="absolute bottom-4 right-4 bg-black/60 text-white text-xs font-bold px-3 py-1 rounded backdrop-blur-md border border-white/10">
                                                Item 2
                                            </div>
                                      </div>
                                 </div>
                            )}
                        </div>

                        <div className="mt-6 text-slate-400 text-sm">
                            {compareMode === 'slider' 
                                ? "Geser slider untuk melihat perbedaan detail antara kedua item."
                                : "Tampilan split screen untuk perbandingan sisi-ke-sisi."
                            }
                        </div>
                    </div>
                </div>
            )}

        </div>
    );
};

export default Gallery;

