                                    }`}
                                    title={favorites.has(selectedItem.id) ? "Hapus dari Favorit" : "Tambah ke Favorit"}
                                >
                                    <Star size={20} fill={favorites.has(selectedItem.id) ? "currentColor" : "none"} />
