                                    <label className="text-xs font-bold text-slate-400 uppercase tracking-wider flex items-center gap-2">
                                        <CheckCircle size={12} /> Prompt AI
                                    </label>
                                    <div className="bg-slate-100 dark:bg-white/5 p-5 rounded-2xl border border-slate-200 dark:border-white/5 text-sm text-slate-700 dark:text-slate-300 leading-relaxed font-medium font-mono">
                                        {selectedItem.prompt}
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="bg-slate-50 dark:bg-white/5 p-4 rounded-2xl border border-slate-200 dark:border-white/5">
