                            className="w-full p-3 bg-slate-50 dark:bg-black/30 border border-slate-200 dark:border-white/10 rounded-xl focus:ring-2 focus:ring-purple-500 outline-none"
                            placeholder="Contoh: Suara Sendiri"
                          />
                      </div>
                      <div className="space-y-2">
                          <label className="text-sm font-bold text-slate-600 dark:text-slate-400">Upload Sample (MP3/WAV)</label>
                          <div 
                             onClick={() => cloneFileInputRef.current?.click()}
                             className="border-2 border-dashed border-slate-300 dark:border-white/20 rounded-xl p-6 text-center cursor-pointer hover:bg-slate-50 dark:hover:bg-white/5 hover:border-purple-500 transition-colors"
                          >
                              {cloneFile ? (
                                  <div className="flex items-center justify-center gap-2 text-purple-500 font-bold">
                                      <FileAudio size={24} /> {cloneFile.name}
                                  </div>
                              ) : (
                                  <div className="flex flex-col items-center gap-2 text-slate-400">
                                      <UploadCloud size={24} />
                                      <span className="text-xs">Klik untuk upload file audio (min 10 detik)</span>
                                  </div>
                              )}
                          </div>
                          <input 
                            type="file" 
                            ref={cloneFileInputRef} 
                            onChange={handleCloneFileChange} 
                            accept="audio/*" 
                            className="hidden" 
                          />
                      </div>

                      {error && (
                        <div className="text-xs text-red-500 bg-red-50 dark:bg-red-900/10 p-2 rounded flex items-center gap-1">
                             <AlertCircle size={12} /> {error}
                        </div>
                      )}
                  </div>
                  <div className="p-5 border-t border-slate-200 dark:border-white/10 bg-slate-50 dark:bg-white/5 flex justify-end">
                      <button 
                        onClick={handleCloneSubmit}
                        disabled={isCloning}
                        className="px-6 py-2.5 bg-purple-600 hover:bg-purple-500 text-white font-bold rounded-xl shadow-lg shadow-purple-500/20 disabled:opacity-50 flex items-center gap-2"
                      >
                          {isCloning ? <Loader2 size={16} className="animate-spin" /> : <Wand2 size={16} />}
                          {isCloning ? 'Memproses AI...' : 'Clone Suara'}
                      </button>
                  </div>
              </div>
          </div>
      )}

      {/* Fullscreen Preview */}
      {previewImage && (
         <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4">
             <button onClick={() => setPreviewImage(null)} className="absolute top-6 right-6 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white">
                 <X size={24} />
             </button>
             <img src={previewImage} className="max-w-full max-h-full rounded shadow-2xl" alt="Preview" />
         </div>
      )}

    </div>
  );
};

export default ImageMerger;

import React, { useState, useRef, useEffect } from 'react';
import { Upload, X, Plus, Wand2, Sparkles, AlertCircle, ArrowLeft, ArrowRight, ImagePlus, Video, Settings2, RefreshCw, FileDown, History, Clock, Trash2, Maximize2, Download, Monitor, Check, ZoomIn, ZoomOut, RotateCcw, Users, Link as LinkIcon, FileAudio, FileVideo, Info, BookOpen, Zap, ChevronDown, Square, RectangleHorizontal, RectangleVertical, Ratio, Tag, Key, HelpCircle, AlertTriangle, BrainCircuit, ArrowUpCircle, Palette, Shirt, Ruler, UserSquare, CheckCircle, Image as ImageIcon, Crown, Gauge, AudioLines, Mic, Play, Pause, Music, FileText, Loader2, UserPlus, UploadCloud, Fingerprint, Film, Sliders } from 'lucide-react';
import { UploadedImage, AspectRatio, FeatureConfig, FeatureMode, HistoryItem } from '../types';
import { generateImage, generateVideo, generateBatchImages, enhancePrompt, generateSpeech } from '../services/geminiService';
import { generateWithPollinations } from '../services/pollinationsService';
import { upscaleImage } from '../services/huggingfaceService';
import { processVideoLink, DownloadResult } from '../services/downloaderService';
import { PromptLibrary } from './PromptLibrary';
import { FeatureExample } from './FeatureExamples';

interface ImageMergerProps {
  feature: FeatureConfig;
  onNavigate: (mode: FeatureMode) => void;
}

const MAX_PROMPT_LENGTH = 5000; 

const PREDEFINED_VOICES = [
    { id: 'Kore', label: 'Kore', desc: 'Wanita - Tenang & Jelas', gender: 'F' },
    { id: 'Zephyr', label: 'Zephyr', desc: 'Wanita - Lembut & Empati', gender: 'F' },
    { id: 'Puck', label: 'Puck', desc: 'Pria - Energik & Ceria', gender: 'M' },
    { id: 'Charon', label: 'Charon', desc: 'Pria - Berat & Dalam', gender: 'M' },
    { id: 'Fenrir', label: 'Fenrir', desc: 'Pria - Berwibawa & Kuat', gender: 'M' },
];

const getImageLabel = (index: number, mode: FeatureMode) => {
  if (mode === 'faceswap') return index === 0 ? 'SUMBER WAJAH (Face)' : 'TARGET FOTO (Body)';
  if (mode === 'videofaceswap') return index === 0 ? 'Wajah (Sumber)' : `Ref #${index + 1}`;
  if (mode === 'fitting') return index === 0 ? 'Model/Orang' : 'Baju/Garmen';
  if (mode === 'prewedding') return index === 0 ? 'Foto Pria' : 'Foto Wanita';
  if (mode === 'mockup') return index === 0 ? 'Desain/Logo' : 'Objek Mockup';
  if (mode === 'veo') return index === 0 ? 'Referensi Awal' : `Ref #${index + 1}`;
  if (mode === 'removebg' || mode === 'removeobj') return 'Foto Asli';
  if (mode === 'fotomodel') return 'Foto Produk / Baju';
  if (mode === 'banana') return 'Reference (Opt)';
  if (mode === 'passphoto') return 'Foto Asli';
  return `#${index + 1}`;
};

const ImageMerger: React.FC<ImageMergerProps> = ({ feature, onNavigate }) => {
  const [images, setImages] = useState<UploadedImage[]>([]);
  const [prompt, setPrompt] = useState<string>(feature.defaultPrompt);
  const [ratio, setRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [showPromptLib, setShowPromptLib] = useState(false);
  const [aiEngine, setAiEngine] = useState<'gemini' | 'pollinations'>('gemini');
  const [generatedResults, setGeneratedResults] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [videoQuality, setVideoQuality] = useState<'720p' | '1080p' | '4k'>('1080p');
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [downloadingQuality, setDownloadingQuality] = useState<string | null>(null);
  const [isUpscaling, setIsUpscaling] = useState(false);
  const [downloadUrlInput, setDownloadUrlInput] = useState('');
  const [downloadProgress, setDownloadProgress] = useState(0);
  const [downloadResult, setDownloadResult] = useState<DownloadResult | null>(null);
  const [genProgress, setGenProgress] = useState<{ current: number; total: number }>({ current: 0, total: 0 });

  // Advanced Settings State
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [negativePrompt, setNegativePrompt] = useState('ugly, blurry, low quality, distortion, watermark, text, deformed, bad anatomy');
  const [seed, setSeed] = useState<number | null>(null);
  const [customSeed, setCustomSeed] = useState(false);

  // TTS State
  const [voiceName, setVoiceName] = useState('Kore');
  const [customVoices, setCustomVoices] = useState<any[]>([]);
  const [showCloneModal, setShowCloneModal] = useState(false);
  const [cloneName, setCloneName] = useState('');
  const [cloneFile, setCloneFile] = useState<File | null>(null);
  const [isCloning, setIsCloning] = useState(false);

  // Video Input State
  const [videoFile, setVideoFile] = useState<{file: File, preview: string} | null>(null);
  const videoRef = useRef<HTMLInputElement>(null);

  // Model Customization State
  const [modelGender, setModelGender] = useState('Wanita');
  const [modelAge, setModelAge] = useState('Dewasa Muda (20-28 thn)');
  const [modelRace, setModelRace] = useState('Asia (Indonesia/Melayu)');

  // Pas Foto State
  const [passBg, setPassBg] = useState('Merah');
  const [passOutfit, setPassOutfit] = useState('Kemeja Putih Polos');
  const [passSize, setPassSize] = useState('4x6');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const cloneFileInputRef = useRef<HTMLInputElement>(null);

  const isVideoMode = feature.type === 'video';
  const isAudioMode = feature.type === 'audio';
  const isDownloaderMode = feature.type === 'downloader';
  const isTextToImage = feature.id === 'imagine'; 
  const isFaceSwap = feature.id === 'faceswap';
  const isPassPhoto = feature.id === 'passphoto';

  useEffect(() => {
    try {
      const savedHistory = localStorage.getItem('andri_ai_history');
      if (savedHistory) {
        setHistory(JSON.parse(savedHistory));
      }
      const savedVoices = localStorage.getItem('andri_ai_custom_voices');
      if (savedVoices) {
          setCustomVoices(JSON.parse(savedVoices));
      }
    } catch (e) {
      console.error("Failed to load history/voices", e);
    }
  }, []);

  useEffect(() => {
    setImages([]);
    setVideoFile(null); // Reset video
    setPrompt(feature.defaultPrompt);
    setGeneratedResults([]);
    setError(null);
    setRatio(AspectRatio.SQUARE);

    // Reset Advanced
    setNegativePrompt('ugly, blurry, low quality, distortion, watermark, text, deformed, bad anatomy');
    setCustomSeed(false);
    setSeed(null);
    setShowAdvanced(false);

    if (feature.id === 'banana') {
        setAiEngine('pollinations');
    } else {
        setAiEngine('gemini');
    }

    setDownloadUrlInput('');
    setDownloadProgress(0);
    setDownloadResult(null);
    setGenProgress({ current: 0, total: 0 });

    if (isVideoMode) {
        setRatio(AspectRatio.LANDSCAPE);
        setVideoQuality('1080p');
    }
    if (feature.id === 'passphoto') {
        setRatio(AspectRatio.PORTRAIT_4_5); 
    }
  }, [feature, isVideoMode]);

  const handlePromptChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    if (val.length <= MAX_PROMPT_LENGTH) {
      setPrompt(val);
      setError(null);
    }
  };

  const handleMagicPrompt = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      const enhanced = await enhancePrompt(prompt);
      setPrompt(enhanced);
    } catch (e) {
      // ignore
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newImages = Array.from(e.target.files).map((file: File) => ({
        id: Math.random().toString(36).substr(2, 9),
        file,
        previewUrl: URL.createObjectURL(file),
      }));
      setImages((prev) => [...prev, ...newImages]);
    }
  };

  const removeImage = (id: string) => {
    setImages((prev) => prev.filter((img) => img.id !== id));
  };

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
        const file = e.target.files[0];
        setVideoFile({
            file,
            preview: URL.createObjectURL(file)
        });
    }
  };

  const handleCloneFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
          setCloneFile(e.target.files[0]);
      }
  };

  const handleCloneSubmit = async () => {
      if (!cloneName.trim()) {
          setError("Nama suara wajib diisi.");
          return;
      }
      if (!cloneFile) {
          setError("File sample suara wajib diupload.");
          return;
      }

      setIsCloning(true);
      setError(null);

      try {
          await new Promise(resolve => setTimeout(resolve, 2000));

          const newVoice = {
              id: `custom-${Date.now()}`,
              label: cloneName,
              desc: 'Custom Cloned Voice',
              gender: 'AI',
              isCustom: true
          };

          const updatedVoices = [...customVoices, newVoice];
          setCustomVoices(updatedVoices);
          localStorage.setItem('andri_ai_custom_voices', JSON.stringify(updatedVoices));

          setVoiceName(newVoice.id);
          setShowCloneModal(false);
          setCloneName('');
          setCloneFile(null);
      } catch (e) {
          setError("Gagal melakukan cloning suara.");
      } finally {
          setIsCloning(false);
      }
  };

  const deleteCustomVoice = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if (confirm('Hapus suara custom ini?')) {
          const updated = customVoices.filter(v => v.id !== id);
          setCustomVoices(updated);
          localStorage.setItem('andri_ai_custom_voices', JSON.stringify(updated));
          if (voiceName === id) setVoiceName('Kore');
      }
  };

  const handleGenerate = async () => {
    // Validation
    if (!isAudioMode && !isDownloaderMode) {
        if (feature.id === 'videofaceswap') {
            if (images.length === 0) {
                setError("Silakan upload gambar wajah sumber.");
                return;
            }
            if (!videoFile) {
                setError("Silakan upload video target.");
                return;
            }
        } else if (images.length < feature.minImages) {
          setError(`Minimal upload ${feature.minImages} gambar untuk fitur ini.`);
          return;
        }
        if (images.length > feature.maxImages && feature.maxImages > 0) {
          setError(`Maksimal upload ${feature.maxImages} gambar.`);
          return;
        }
    }
    if (!prompt.trim() && !isPassPhoto && !isDownloaderMode && feature.id !== 'videofaceswap') {
       setError("Instruksi tidak boleh kosong.");
       return;
    }

    setLoading(true);
    setError(null);
    setGeneratedResults([]);
    setGenProgress({ current: 0, total: 0 });

    try {
      let results: string[] = [];
      let finalPrompt = prompt;

      // Special Prompts Construction
      if (feature.id === 'fotomodel') {
         finalPrompt = `Target: Professional Fashion Photography. Model: ${modelGender}, ${modelAge}, ${modelRace}. Action: Wearing the product shown in input image. Context: ${prompt}. Quality: 8k, photorealistic.`;
      }
      if (feature.id === 'passphoto') {
         finalPrompt = `Pas Foto Formal Resmi. Background: ${passBg}. Outfit: ${passOutfit}. Subjek: Wajah dari gambar input. Pencahayaan studio rata, ekspresi netral, mata menatap kamera, resolusi tinggi, tajam.`;
      }

      // Prepare Options
      const options = {
          negativePrompt: negativePrompt,
          seed: customSeed && seed ? seed : undefined
      };

      // --- EXECUTION BLOCK ---

      // 1. Text to Speech
      if (isAudioMode) {
          const audioBase64 = await generateSpeech(prompt, voiceName);
          results = [audioBase64];
      }
      // 2. Video Generation
      else if (isVideoMode) {
         if (feature.id === 'videofaceswap' && videoFile) {
             const videoUrl = await generateVideo(finalPrompt, images, ratio, feature.id, videoQuality);
             results = [videoUrl];
         } else {
             const videoUrl = await generateVideo(finalPrompt, images, ratio, feature.id, videoQuality);
             results = [videoUrl];
         }
      }
      // 3. Fast Image (Banana/Pollinations)
      else if (aiEngine === 'pollinations') {
         let w = 1024, h = 1024;
         if (ratio === AspectRatio.LANDSCAPE) { w = 1280; h = 720; }
         if (ratio === AspectRatio.PORTRAIT) { w = 720; h = 1280; }
         if (ratio === AspectRatio.PORTRAIT_4_5) { w = 864; h = 1080; }

         const imageUrl = await generateWithPollinations(finalPrompt, w, h, 2, options.negativePrompt, options.seed);
         results = [imageUrl];
      }
      // 4. Gemini Image Generation
      else {
         if (feature.id === 'banana') {
            results = await generateBatchImages(finalPrompt, images, ratio, feature.id, 4, (c, t) => setGenProgress({current:c, total:t}));
         } else {
            const result = await generateImage(finalPrompt, images, ratio, feature.id, 2, false, options);
            results = [result];
         }
      }

      setGeneratedResults(results);

      // Save to History
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        mode: feature.id,
        prompt: finalPrompt + (options.negativePrompt ? ` | Negative: ${options.negativePrompt}` : ''),
        results: results,
        thumbnail: results[0],
        type: feature.type || 'image'
      };

      const updatedHistory = [newHistoryItem, ...history];
      setHistory(updatedHistory);
      localStorage.setItem('andri_ai_history', JSON.stringify(updatedHistory));

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Gagal memproses permintaan. Silakan coba lagi.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadUrl = async () => {
     if (!downloadUrlInput) { setError("URL tidak boleh kosong"); return; }
     setLoading(true);
     setDownloadProgress(10);
     try {
        const result = await processVideoLink(downloadUrlInput, feature.id, 'mp4-1080p', (p) => setDownloadProgress(p));
        setDownloadResult(result);
     } catch(e: any) {
        setError(e.message);
     } finally {
        setLoading(false);
     }
  };

  // --- UI COMPONENTS ---

  const renderVoiceSelector = () => (
    <div className="mb-6 animate-in fade-in slide-in-from-left-4">
        {/* Voice Selector Content */}
        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 flex items-center justify-between">
            <span className="flex items-center gap-2"><Mic size={16} className="text-emerald-500" /> Pilih Suara AI</span>
            <span className="text-[10px] text-slate-400 bg-slate-100 dark:bg-white/10 px-2 py-0.5 rounded-full">{customVoices.length + PREDEFINED_VOICES.length} Suara Tersedia</span>
        </label>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-h-60 overflow-y-auto custom-scrollbar pr-1">
             {[...PREDEFINED_VOICES, ...customVoices].map((voice) => (
                 <div 
                    key={voice.id}
                    onClick={() => setVoiceName(voice.id)}
                    className={`relative cursor-pointer p-3 rounded-xl border transition-all flex items-center gap-3 group ${
                        voiceName === voice.id 
                        ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-500 ring-1 ring-emerald-500' 
                        : 'bg-white dark:bg-white/5 border-slate-200 dark:border-white/10 hover:border-emerald-300'
                    }`}
                 >
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${
                        voiceName === voice.id ? 'bg-emerald-500 text-white' : 'bg-slate-200 dark:bg-white/10 text-slate-500'
                    }`}>
                        {voice.isCustom ? <Fingerprint size={14} /> : voice.gender}
                    </div>
                    <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                             <div className="font-bold text-slate-700 dark:text-slate-200 text-sm truncate">{voice.label}</div>
                             {voice.isCustom && <span className="text-[9px] bg-purple-100 text-purple-600 px-1.5 py-0.5 rounded font-bold uppercase">Clone</span>}
                        </div>
                        <div className="text-[10px] text-slate-500 dark:text-slate-400 truncate">{voice.desc}</div>
                    </div>

                    {voice.isCustom && (
                        <button 
                            onClick={(e) => deleteCustomVoice(e, voice.id)}
                            className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded opacity-0 group-hover:opacity-100 transition-all"
                            title="Hapus Suara"
                        >
                            <Trash2 size={12} />
                        </button>
                    )}

                    {voiceName === voice.id && <CheckCircle size={16} className="ml-auto text-emerald-500 shrink-0" />}
                 </div>
             ))}

             <button 
                onClick={() => setShowCloneModal(true)}
                className="p-3 rounded-xl border-2 border-dashed border-slate-300 dark:border-white/20 hover:border-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/10 transition-all flex items-center justify-center gap-2 group min-h-[70px]"
             >
                 <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-white/10 group-hover:bg-emerald-500 group-hover:text-white flex items-center justify-center transition-colors">
                     <UserPlus size={16} />
                 </div>
                 <div className="text-left">
                     <div className="font-bold text-slate-600 dark:text-slate-300 text-sm group-hover:text-emerald-600 dark:group-hover:text-emerald-400">Clone Suara</div>
                     <div className="text-[10px] text-slate-400">Tambah suara baru</div>
                 </div>
             </button>
        </div>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800 dark:text-white flex items-center gap-3">
            <div className="p-2 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl shadow-lg shadow-emerald-500/20 text-white">
               {feature.icon || <Sparkles size={24} />}
            </div>
            {feature.title}
          </h2>
          <p className="text-slate-500 dark:text-slate-400 mt-1 text-sm md:text-base max-w-2xl">
            {feature.description}
          </p>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">

        {/* LEFT COLUMN - CONTROLS */}
        <div className="w-full lg:w-[420px] shrink-0 space-y-6">

            {/* Input Section */}
            <div className="bg-white dark:bg-[#0c0c0e] p-6 rounded-3xl shadow-xl border border-slate-200 dark:border-white/10 relative overflow-hidden">

                {/* 1. Downloader Input */}
                {isDownloaderMode && (
                    <div className="mb-6">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Link Video {feature.title.split(' ')[0]}</label>
                        <div className="flex gap-2">
                             <input 
                                type="text"
                                value={downloadUrlInput}
                                onChange={(e) => setDownloadUrlInput(e.target.value)}
                                className="flex-1 p-3 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none"
                                placeholder={`Tempel link ${feature.title.split(' ')[0]} disini...`}
                             />
                        </div>
                    </div>
                )}

                {/* 2. Audio/TTS Voice Selector */}
                {isAudioMode && renderVoiceSelector()}

                {/* 3. Image Uploaders */}
                {!isAudioMode && !isDownloaderMode && (feature.maxImages > 0) && (
                    <div className="mb-6">
                         <div className="flex justify-between items-center mb-3">
                            <label className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                                <ImagePlus size={16} className="text-emerald-500" />
                                Upload Gambar Referensi
                            </label>
                            <span className="text-xs font-medium bg-slate-100 dark:bg-white/10 px-2 py-1 rounded text-slate-500">
                                {images.length} / {feature.maxImages === 0 ? '∞' : feature.maxImages}
                            </span>
                        </div>

                        <div className="grid grid-cols-2 gap-3 mb-3">
                            {images.map((img, idx) => (
                                <div key={img.id} className="relative aspect-square rounded-xl overflow-hidden border border-slate-200 dark:border-white/10 group bg-slate-100 dark:bg-white/5">
                                    <img src={img.previewUrl} alt="Upload" className="w-full h-full object-cover" />
                                    <button 
                                        onClick={() => removeImage(img.id)}
                                        className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-md"
                                    >
                                        <X size={12} />
                                    </button>
                                    <div className="absolute bottom-0 left-0 right-0 bg-black/60 text-white text-[10px] py-1 px-2 text-center backdrop-blur-sm truncate">
                                        {getImageLabel(idx, feature.id)}
                                    </div>
