                                                Item 2
                                            </div>
                                      </div>
                                 </div>
                            )}
                        </div>

                        <div className="mt-6 text-slate-400 text-sm">
                            {compareMode === 'slider' 
                                ? "Geser slider untuk melihat perbedaan detail antara kedua item."
                                : "Tampilan split screen untuk perbandingan sisi-ke-sisi."
                            }
                        </div>
                    </div>
                </div>
            )}

        </div>
    );
};

