 */
export const saveHistoryWithPruning = (newItem: HistoryItem) => {
    try {
        const saved = localStorage.getItem('andri_ai_history');
        let history: HistoryItem[] = saved ? JSON.parse(saved) : [];

        // Add new item at the beginning
        history = [newItem, ...history];

        // Try saving
        try {
            localStorage.setItem('andri_ai_history', JSON.stringify(history));
        } catch (e: any) {
            if (e.name === 'QuotaExceededError' || e.code === 22) {
                console.warn("LocalStorage full, pruning oldest 5 items...");
                // Remove oldest 5 items and try again
                while (history.length > 5) {
                    history = history.slice(0, history.length - 5);
                    try {
                        localStorage.setItem('andri_ai_history', JSON.stringify(history));
                        break; // Success
                    } catch (innerE) {
                        // Still full, loop again
                    }
                }
            } else {
                throw e;
            }
        }
    } catch (err) {
        console.error("Critical error saving history:", err);
    }
};

