      // 1. Text to Speech
      if (isAudioMode) {
          const selectedVoice = [...PREDEFINED_VOICES, ...customVoices].find(v => v.id === voiceName);
          const sampleAudio = selectedVoice?.isCustom ? { data: selectedVoice.sampleData, mimeType: selectedVoice.mimeType } : undefined;
          const audioBase64 = await generateSpeech(prompt, voiceName, sampleAudio);
          results = [audioBase64];
      }
      // 2. Video Generation
      else if (isVideoMode) {
         if (feature.id === 'videofaceswap' && videoFile) {
             const videoUrl = await generateVideo(finalPrompt, images, ratio, feature.id, videoQuality);
             results = [videoUrl];
         } else {
             const videoUrl = await generateVideo(finalPrompt, images, ratio, feature.id, videoQuality);
             results = [videoUrl];
         }
      }
      // 3. Fast Image (Banana/Pollinations)
      else if (aiEngine === 'pollinations') {
         let w = 1024, h = 1024;
         if (ratio === AspectRatio.LANDSCAPE) { w = 1280; h = 720; }
         if (ratio === AspectRatio.PORTRAIT) { w = 720; h = 1280; }
         if (ratio === AspectRatio.PORTRAIT_4_5) { w = 864; h = 1080; }

         const imageUrl = await generateWithPollinations(finalPrompt, w, h, 2, options.negativePrompt, options.seed);
         results = [imageUrl];
      }
      // 4. Gemini Image Generation
      else {
         if (feature.id === 'banana') {
            results = await generateBatchImages(finalPrompt, images, ratio, feature.id, 4, (c, t) => setGenProgress({current:c, total:t}));
         } else {
            const result = await generateImage(finalPrompt, images, ratio, feature.id, 2, false, options);
            results = [result];
         }
      }

      setGeneratedResults(results);

      // Save to History using Pruning to avoid QuotaExceededError
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        mode: feature.id,
        prompt: finalPrompt + (options.negativePrompt ? ` | Negative: ${options.negativePrompt}` : ''),
        results: results,
        thumbnail: results[0],
        type: feature.type || 'image'
      };

      saveHistoryWithPruning(newHistoryItem);
      // Refresh local history state
      const saved = localStorage.getItem('andri_ai_history');
      if (saved) setHistory(JSON.parse(saved));

    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Gagal memproses permintaan. Silakan coba lagi.');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadUrl = async () => {
     if (!downloadUrlInput) { setError("URL tidak boleh kosong"); return; }
     setLoading(true);
     setDownloadProgress(10);
     try {
        const result = await processVideoLink(downloadUrlInput, feature.id, 'mp4-1080p', (p) => setDownloadProgress(p));
        setDownloadResult(result);
     } catch(e: any) {
        setError(e.message);
     } finally {
        setLoading(false);
     }
  };

  return (
    <div className="flex flex-col gap-6 p-4 max-w-4xl mx-auto">
        <header className="flex flex-col gap-2">
            <h1 className="text-3xl font-bold flex items-center gap-2">
                {feature.icon} {feature.title}
            </h1>
            <p className="text-slate-500">{feature.description}</p>
        </header>

        <section className="bg-white dark:bg-[#0c0c0e] p-6 rounded-2xl border border-slate-200 dark:border-white/10 shadow-sm">
            {/* Component Content rendering prompt, images upload, etc */}
            <div className="flex flex-col gap-4">
                <textarea 
                    value={prompt}
                    onChange={handlePromptChange}
                    className="w-full p-3 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl outline-none"
                    placeholder="Masukkan instruksi..."
                />
                <button 
                    onClick={handleGenerate}
                    disabled={loading}
                    className="bg-emerald-500 text-white font-bold py-3 px-6 rounded-xl hover:bg-emerald-600 transition-colors flex items-center justify-center gap-2"
                >
                    {loading ? <Loader2 className="animate-spin" /> : <Sparkles />} Generate {feature.title}
                </button>
            </div>
        </section>

        {generatedResults.length > 0 && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
