                                <div className="flex justify-center gap-4">
                                    <button 
                                        onClick={() => setShowCompare(!showCompare)}
                                        className={`px-6 py-2.5 rounded-full text-xs font-black transition-all flex items-center gap-2 border ${showCompare ? 'bg-indigo-600 text-white border-indigo-700' : 'bg-white dark:bg-white/5 border-slate-200 dark:border-white/10 text-slate-600 dark:text-slate-400'}`}
                                    >
                                        <ArrowLeftRight size={16} /> {showCompare ? 'MATIKAN COMPARE' : 'BANDINGKAN HASIL'}
                                    </button>
                                </div>
                             )}

                            {showCompare && generatedResults[0] && images[0] ? (
                                <div className="relative w-full aspect-square rounded-[2rem] overflow-hidden border-4 border-white dark:border-white/10 shadow-2xl scanline-effect group">
                                    <img src={generatedResults[0]} className="absolute inset-0 w-full h-full object-contain" />
                                    <div 
                                        className="absolute inset-0 w-full h-full border-r-2 border-white z-10 overflow-hidden"
                                        style={{ width: `${sliderPos}%` }}
                                    >
                                        <img src={images[0].previewUrl} className="absolute inset-0 w-[100%] h-full object-contain bg-slate-100" />
                                        <div className="absolute top-4 left-4 bg-white text-black px-3 py-1 rounded text-[10px] font-black shadow-lg">BEFORE (ASLI)</div>
                                    </div>
                                    <div className="absolute top-4 right-4 bg-emerald-500 text-white px-3 py-1 rounded text-[10px] font-black shadow-lg">AFTER (AI)</div>

                                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20 pointer-events-none" style={{ left: `${sliderPos}%` }}>
                                        <div className="w-10 h-10 bg-white rounded-full shadow-2xl flex items-center justify-center border-4 border-indigo-500 scale-110">
                                            <ArrowLeftRight size={20} className="text-indigo-500" />
                                        </div>
                                    </div>

                                    <input 
                                        type="range" min="0" max="100" value={sliderPos}
                                        onChange={(e) => setSliderPos(Number(e.target.value))}
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-ew-resize z-30"
                                    />
                                </div>
                            ) : (
                                <div className="w-full grid gap-4">
                                    {generatedResults.map((res, i) => (
                                        <div key={i} className="bg-slate-50 dark:bg-[#151517] p-4 rounded-[2rem] shadow-2xl border border-slate-200 dark:border-white/5 group">
                                            {isAudioMode ? (
                                                <div className="flex flex-col items-center gap-6 p-8">
                                                    <div className="w-24 h-24 bg-gradient-to-tr from-emerald-500 to-teal-600 text-white rounded-full flex items-center justify-center shadow-2xl scale-110"><Music size={40}/></div>
                                                    <div className="w-full bg-slate-200 dark:bg-white/10 p-4 rounded-3xl">
                                                        <audio controls src={res} className="w-full h-10" />
                                                    </div>
                                                    <a href={res} download="Indigital-Audio.wav" className="px-10 py-4 bg-slate-900 text-white rounded-2xl text-sm font-black flex items-center gap-3 shadow-xl hover:bg-black transition-all active:scale-95"><Download size={20}/> DOWNLOAD AUDIO (WAV)</a>
                                                </div>
                                            ) : (
                                                <div className="relative overflow-hidden rounded-2xl">
                                                    {isVideoMode ? <video src={res} controls className="w-full h-auto rounded-2xl" /> : <img src={res} className="w-full h-auto rounded-2xl" />}
                                                    <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-all duration-300 flex items-center justify-center gap-6 backdrop-blur-sm">
                                                        <button onClick={() => window.open(res)} className="p-4 bg-white text-black rounded-2xl shadow-2xl hover:scale-110 transition-transform"><Maximize2 size={24}/></button>
                                                        <a href={res} download="Indigital-Result" className="p-4 bg-emerald-500 text-white rounded-2xl shadow-2xl hover:scale-110 transition-transform"><Download size={24}/></a>
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="text-slate-400 flex flex-col items-center gap-6">
                            <div className="w-24 h-24 rounded-full border-4 border-dashed border-slate-300 dark:border-white/10 flex items-center justify-center animate-spin-slow">
                                <Sparkles size={48} className="opacity-20" />
                            </div>
                            <div>
                                <h3 className="text-xl font-black text-slate-600 dark:text-slate-500 tracking-tighter uppercase mb-2">Belum Ada Hasil</h3>
                                <p className="text-xs font-bold text-slate-400 tracking-widest leading-relaxed">Isi prompt dan tekan tombol <br/> GENERASI untuk memulai.</p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>

        {showCloneModal && (
            <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
                <div className="bg-white dark:bg-[#1a1a1c] w-full max-w-md rounded-[3rem] shadow-[0_0_100px_rgba(0,0,0,0.5)] p-10 border border-white/10 animate-in zoom-in-95">
                    <h3 className="text-2xl font-black mb-8 flex items-center gap-3 tracking-tighter"><UserPlus size={28} className="text-emerald-500"/> CLONE SUARA</h3>
                    <div className="flex flex-col gap-6">
                        <div className="flex flex-col gap-3">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama Karakter</label>
                            <input value={cloneName} onChange={e => setCloneName(e.target.value)} type="text" className="p-4 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-500 font-bold" placeholder="Contoh: Suara Artis X" />
                        </div>
                        <div className="flex flex-col gap-3">
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Contoh Suara (MP3/WAV)</label>
                            <div onClick={() => cloneFileInputRef.current?.click()} className="p-10 border-2 border-dashed border-slate-200 dark:border-white/10 rounded-3xl flex flex-col items-center gap-3 cursor-pointer hover:bg-slate-50 dark:hover:bg-white/5 transition-all">
                                {cloneFile ? (
                                    <div className="flex flex-col items-center gap-2 text-emerald-500 font-black">
                                        <Music size={32} className="animate-bounce" /> 
                                        <span className="text-sm truncate max-w-[250px]">{cloneFile.name}</span>
                                    </div>
                                ) : (
                                    <>
                                        <UploadCloud className="text-slate-300" size={40}/>
                                        <div className="text-center">
                                            <span className="text-[10px] font-black text-slate-500 uppercase block">Klik Untuk Upload</span>
                                            <span className="text-[9px] font-bold text-slate-400 mt-1">Gunakan rekaman bersih durasi min 10 detik</span>
                                        </div>
                                    </>
                                )}
                            </div>
                            <input type="file" ref={cloneFileInputRef} onChange={e => setCloneFile(e.target.files?.[0] || null)} className="hidden" accept="audio/*" />
                        </div>
                        <div className="flex gap-4 mt-4">
                            <button onClick={() => setShowCloneModal(false)} className="flex-1 py-4 border-2 border-slate-200 dark:border-white/10 rounded-2xl font-black text-slate-500 hover:bg-slate-50 dark:hover:bg-white/5">BATAL</button>
                            <button onClick={handleCloneSubmit} disabled={isCloning} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-xl shadow-emerald-500/30 flex items-center justify-center gap-3">
                                {isCloning ? <Loader2 size={20} className="animate-spin" /> : 'MULAI CLONE'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default ImageMerger;
